INSERT INTO "public"."plan_items" ("id", "title", "description", "frequency", "category", "sort_order", "is_active", "created_at", "updated_at", "target_count") VALUES
	('87e0fb80-605a-48c7-b8f4-495d4e8bec9c', '全天 膽鹼攝取確認（目標 AI 550mg）', '每日確認膽鹼攝取達 AI 550mg。主力來源：雞蛋 4 顆/日（~560mg，蛋黃為核心）——⚠️ 嚴格 4 顆最低標準，3 顆僅 420mg 不達 AI。分配：非牛肉日 1 顆 15:30 + 3 顆晚餐；牛肉日 1-2 顆午餐 + 1 顆 15:30 + 晚餐補足。⚠️ 牛肉日雞蛋可能僅 2-3 顆（蛋白質額度被牛肉佔用），需額外補充：卵磷脂 1.5 大匙（~180mg）確保達 AI 550mg。⚠️ 豆腐日 / 低膽鹼蛋白日（非雞肉/鮭魚/牛肉）：即使 4 顆蛋（560mg）已達 AI，仍建議卵磷脂 1 大匙（~120mg）作為緩衝。膽鹼對肝臟脂肪代謝、神經傳導、甲基化代謝至關重要', 'daily', '飲食', 29, true, '2026-03-01 06:18:05.208027+00', '2026-03-01 06:18:05.208027+00', 1),
	('e8904294-3f22-49c7-9b03-62e88c20d6f5', '全天 膳食纖維 35-45g', '洋蔥、大蒜、蘆筍、燕麥、扁豆、酪梨、冷卻米飯/地瓜（抗性澱粉）。搭配發酵食物（優格、泡菜 ≤30g/日）增強腸道多樣性。⚠️ 訓練日注意：低纖維碳水替換（白米/義大利麵/去皮馬鈴薯）可能使纖維降至 20-25g。訓練日補充：奇亞籽 15g（5g 纖維 09:15）+ 洋車前子殼 5g 午餐前 11:45 + 5g 下午點心 15:30（共 8g 纖維）= 額外 13g，搭配蔬菜 5-8g 達標 35g+。🔴 洋車前子殼已從 09:15 移除（避免訓練前 GI 不適），改為午餐前 + 下午點心。晚餐前不用（保護 CoQ10/K2 脂溶性吸收）。🔴 葉酸保險：B群休息日（隔日無 B-complex），15:30 點心加入浸泡扁豆/鷹嘴豆 100g（~180mcg 葉酸 + 6-8g 纖維）——浸泡 8hr+ 可減少植酸 50-70%，確保每日葉酸 ≥400mcg DFE', 'daily', '飲食', 22, true, '2026-02-15 16:39:36.29248+00', '2026-02-15 16:39:36.29248+00', 1),
	('f67a7189-efb4-42e6-946b-398a6be4c1da', '17:00 高質量社交對話', '至少與一位親友進行非公事的深度對話。每週安排 1 次面對面社交活動。戶外自然接觸 120+ 分鐘/週（可結合有氧）。哈佛研究：人際關係品質對壽命影響高於飲食與運動', 'daily', '心理', 12, true, '2026-02-15 16:39:36.29248+00', '2026-02-24 09:33:03.116415+00', 1),
	('df5c073f-39a9-44e9-ac14-4f1fbb717cf5', '12:00 午餐 + 訓練後補充品', '蛋白質 35-40g（正餐完整蛋白質，⚠️ 不含膠原蛋白——膠原蛋白缺乏色胺酸與 BCAAs，非合成代謝等效蛋白質，僅作為結締組織修復補充）+ 蔬菜 + 🥑 酪梨半顆（必須，~350mg 鉀 + 7g 纖維 + 健康脂肪）（建議使用白米或冷卻再加熱白米飯以減少植酸干擾鐵吸收）。隨餐服用：魚油 2 顆（鮭魚日 1 顆）、D3 2000IU（2 顆）、葉黃素 20mg、膠原蛋白肽 10-15g（額外，含 VitC ~120-160mg）、維他命C 500mg 1 錠（搭配鐵質食物最大化吸收）、B群 1 顆（⚠️ 每 3 天服用 1 顆，或換 ≤25mg B6 產品後隔日服用）、肌酸 5g（溶於湯/飲品隨餐）。✅ 午餐總脂肪約 27-32g（橄欖油 14g + 酪梨 ~7g + 蛋/魚/肉脂肪），充足支持脂溶性 D3 與葉黃素吸收。⚠️ 堅果/種子請留至 15:30（避免鋅鐵 DMT1 競爭）', 'daily', '飲食', 7, true, '2026-02-16 06:13:21.915132+00', '2026-02-16 14:39:15.949+00', 1),
	('e08ee5cc-a782-47e7-bfcb-920eb51cdb99', '22:30 睡前補充品', '甘胺酸 3g + 甘胺酸鎂 150mg（1.5 錠）+ Ashwagandha 450mg（KSM-66，嚴格 8 週用 / 4 週停）。洗完熱水澡後立即服用。💊 鈣片已移至 17:00（距睡前鎂 5.5hr，無鈣鎂競爭）。💊 Magtein 144mg 已移至 14:00（午餐後 2hr 空腹，避開 15:00 綠茶 EGCG 螯合）。補充品鎂合計 ~294mg（甘胺酸鎂 150mg + 蘇糖酸鎂 144mg PM），安全低於 UL 350mg', 'daily', '補充品', 15, true, '2026-02-15 16:39:36.29248+00', '2026-02-16 14:39:16.269+00', 1),
	('bb8d1cdf-99cc-4163-a532-6f58e33bde70', '訓練日 洋車前子殼 8-10g（纖維補充）', '重訓日低纖維碳水替換（白米/義大利麵/去皮馬鈴薯）會使膳食纖維降至 20-25g，距目標 35g+ 缺口 10-15g。🔴 新分配：午餐前 11:45 洋車前子殼 5g（4g 纖維）+ 下午點心 15:30 洋車前子殼 5g（4g 纖維）= 共 8g 額外纖維。⚠️ 已從 09:15 訓練前移除——訓練前 45 分鐘攝取 8.5g 纖維（原洋車前子殼 5g + 奇亞籽 5g）導致 GI 不適風險高（腹脹、痙攣）。現 09:15 僅剩奇亞籽 ~5g 纖維，可接受。⚠️ 不安排於晚餐前——洋車前子殼結合膽汁酸會降低 28g 橄欖油的脂肪吸收，影響 CoQ10（泛醇）和 K2（MK-7）等脂溶性補充品。15:30 點心無脂溶性補充品，安全。⚠️ 每次必須搭配充足水分（250ml+），否則可能引起腸阻塞。⚠️ 僅訓練日使用——休息日正常飲食纖維已達標 35g+', 'daily', '飲食', 23, true, '2026-03-01 06:18:05.208027+00', '2026-03-01 06:18:05.208027+00', 1),
	('13c95372-82b9-4f5c-815b-19723d59f391', '23:30 Cyclic Sighing + 專注冥想', 'Cyclic Sighing 5 分鐘（雙吸鼻、長呼口，Stanford RCT 證實最佳呼吸法）+ 專注冥想 10 分鐘（單點注意力：鼻尖呼吸）。寫下三件感恩的事', 'daily', '心理', 18, true, '2026-02-15 16:39:36.29248+00', '2026-02-15 16:39:36.29248+00', 1),
	('7d21cdd2-b2cf-4f41-8948-204587c91b6a', '23:50 口腔衛生：刷牙 + 牙線', '早晚各一次。牙周病菌（P. gingivalis）與心血管疾病、阿茲海默症強相關。每日至少刷牙 2 次 + 牙線 1 次', 'daily', '一般', 19, true, '2026-02-16 06:13:21.91934+00', '2026-02-16 06:13:21.91934+00', 1),
	('75217eff-f688-4c39-bea6-428e00f0642f', '22:00 藍光管理', '調暗燈光或佩戴防藍光眼鏡（琥珀色鏡片）。白天：娛樂螢幕 <2hr、社群媒體 <30min、專注時段手機勿擾模式', 'daily', '睡眠', 16, true, '2026-02-15 16:39:36.29248+00', '2026-02-15 16:39:36.29248+00', 1),
	('17327ad6-cb69-4c3f-8680-4069511c5723', '00:00 準時入睡', '目標 8-8.5 小時睡眠。全黑、低溫 18-19°C。深層睡眠啟動腦部排毒系統', 'daily', '睡眠', 20, true, '2026-02-15 16:39:36.29248+00', '2026-02-15 16:39:36.29248+00', 1),
	('a4b34bb0-3b76-4630-b08c-de729827c8c3', '15:00 NSDR', '使用引導式 Yoga Nidra 音檔（非單純休息）。11 分鐘有 RCT 支持，促進深度放鬆與多巴胺恢復', 'daily', '心理', 9, true, '2026-02-15 16:39:36.29248+00', '2026-02-15 16:39:36.29248+00', 1),
	('0dd80cc3-1d47-43bd-9eb3-31606e451c54', '午餐 橄欖油 14g（1 大匙）', '特級初榨橄欖油 1 大匙（14g）入菜或涼拌。確保脂溶性維生素（D3、K2、葉黃素、CoQ10）充分吸收。橄欖油富含單元不飽和脂肪酸（MUFA），支持心血管健康與抗發炎', 'daily', '脂肪', 18, true, '2026-02-27 13:28:21.035466+00', '2026-02-27 13:28:21.035466+00', 1),
	('ff8cc0e9-6544-4969-aca3-3e10eb68fa98', '晚餐 橄欖油 28g（2 大匙）', '特級初榨橄欖油 2 大匙（28g）入菜或涼拌。支持每日脂肪目標 80-90g。晚餐較高脂肪有助於延緩胃排空、穩定血糖、增加飽足感', 'daily', '脂肪', 28, true, '2026-02-27 13:28:21.035466+00', '2026-02-27 13:28:21.035466+00', 1),
	('0ef92d20-57b4-46aa-8643-4d5847b29466', '全天 飲水 4-4.5L（訓練日）/ 3.5L（休息日）', '尿液淡稻草色（非淡黃色）為最佳水合指標。🔴 訓練日 4-4.5L（從 3-3.5L 上調）：73kg 運動員基線 2.5-2.9L + 汗液損失 1-1.5L/次 + 肌酸水分滯留 +500ml + 高蛋白尿素排泄 +300ml。休息日 3.5-4L。💧 補鈣日飲水目標 4L+。📋 訓練日飲水時間表：晨起 500ml（電解質水）→ 訓練前 30min 500ml → 訓練中 500-750ml → 訓練後 30min 500ml → 其餘分散各餐。⚠️ 訓練前後秤體重：每減少 1kg = 需額外補回 1L 水', 'daily', '飲食', 26, true, '2026-02-16 16:39:30.50158+00', '2026-02-16 16:39:30.50158+00', 1),
	('a5382217-5ce1-4133-bb5c-bfd39917d226', '09:15 NMN + TMG（空腹）', '【已停用】成本效益不高 & 當前補充品已涵蓋主要需求。若要恢復，告知後可添加產品到採購清單', 'daily', '補充品', 2, false, '2026-02-15 16:39:36.29248+00', '2026-02-22 14:32:33.841141+00', 1),
	('651abc0d-fbc5-4dc0-b6aa-e5df6e2a7650', '全天 銅攝取確認（目標 ≥0.9mg）', '每日確認飲食銅攝取 ≥0.9mg（RDA）。⚠️ 長期補鋅 15mg/日可導致銅耗竭——鋅誘導腸道金屬硫蛋白（Metallothionein）優先結合銅，阻止銅吸收。必吃銅來源：🍫 黑巧克力 20g（~0.5mg 銅）+ 🥜 綜合堅果 30g（~0.3-0.5mg 銅）+ 可可粉 5g（~0.2mg 銅）= 合計 ~1.0-1.2mg。⚠️ 若任一項缺席，當日銅可能 <0.9mg。銅缺乏症狀：貧血（鐵劑無效型）、白血球低下、骨質疏鬆、神經病變。⚠️ 每半年驗血清銅+銅藍蛋白：銅藍蛋白 <20mg/dL 或血清銅 <70mcg/dL → 立即加回銅補充品 1mg/日', 'daily', '礦物質', 30, true, '2026-03-01 06:47:56.430406+00', '2026-03-01 06:47:56.430406+00', 1),
	('f1dc3889-e4f3-4671-988d-50ea72cb39d5', '09:00 起床 & 晨光曝曬', '起床後 30 分鐘內到戶外曬太陽 10-20 分鐘（陰天久一點）。不戴太陽眼鏡。校正晝夜節律、降低皮質醇、促進維他命D合成', 'daily', '睡眠', 1, true, '2026-02-15 16:39:36.29248+00', '2026-02-15 16:39:36.29248+00', 1),
	('a10d6c70-3875-4ef7-b72a-25c643f56181', '19:30 餐後散步 15 分鐘', '控制餐後血糖最有效的方法，降低胰島素峰值。輕快步行即可，不需高強度。午餐後也建議散步 10-15 分鐘。可結合戶外自然接觸（每週目標 120+ 分鐘）', 'daily', '運動', 14, true, '2026-02-15 16:39:36.29248+00', '2026-02-24 09:33:03.116415+00', 1),
	('c66daa7c-fbe8-4490-b6d9-12477b4ef6f8', '藍莓 50g（抗氧化）', '每日 50g 新鮮或冷凍藍莓。富含花青素（Anthocyanins），A 級證據支持改善認知功能、血管健康、抗氧化。可加入燕麥碗、希臘優格、或作為下午點心（15:30）搭配豌豆蛋白', 'daily', '食物', 20, true, '2026-02-27 13:28:21.035466+00', '2026-02-27 13:28:21.035466+00', 1),
	('ca54886f-93db-40d0-a5c3-d599e6d42891', '10:00 運動', '一上半身A/二下半身A/四上半身B/五下半身B。三 VO2 Max 間歇。六/日 Zone 2 有氧 45-60 分鐘', 'daily', '運動', 5, true, '2026-02-15 16:39:36.29248+00', '2026-02-15 16:39:36.29248+00', 1),
	('70ded901-cc6a-4878-afd3-56ba5d06e4fb', '09:15 咖啡 + L-Theanine（訓練前）', '☕ 起床後 15 分鐘，搭配訓練前營養一起攝取。咖啡因 150-200mg + L-Theanine 200mg（1:1 A 級 nootropic 組合）。咖啡因 ~45-60 分鐘達峰，10:00 訓練時正好最佳狀態。✅ 距午餐 12:00 達 2.75hr+，咖啡多酚對午餐鐵吸收影響降至 15-20%（搭配 VitC 500mg 仍淨正效益）。✅ 距入睡 00:00 達 14.75hr（>5 個半衰期），咖啡因殘留 <5mg，對睡眠影響趨近零。⚠️ CAR（皮質醇覺醒反應）通常 30 分鐘內達峰——起床後 15 分鐘略早，但搭配 L-Theanine 可緩衝焦慮感。若感覺過度亢奮可延至 09:30', 'daily', '飲食', 3, true, '2026-02-15 16:39:36.29248+00', '2026-02-15 16:39:36.29248+00', 1),
	('6027dcfd-15fb-4d34-a7e1-b0dca080d803', '全天 每 45 分鐘站立/坐姿切換', '維持脂蛋白脂肪酶 LPL 活性，避免久坐代謝下降', 'daily', '運動', 23, true, '2026-02-15 16:39:36.29248+00', '2026-02-15 16:39:36.29248+00', 1),
	('239f5306-7419-4fdb-a85b-2b6ca7a9bbd9', '全天 鐵吸收最佳化確認（目標 RDA 8mg）', '每日確認鐵吸收最佳化（男性 RDA 8mg）。🔴 鐵吸收促進因子：(1) 維他命C 午餐 500mg + 晚餐 250mg 隨餐（促進非血基質鐵吸收 2-6 倍）✅。(2) 動物蛋白「肉類因子」（MFP）促進鐵吸收。(3) 鈣片已移至 17:00——午餐/晚餐鐵均不再被鈣抑制（距晚餐 2hr）✅。(4) 堅果/種子移至 15:30——午餐/晚餐無鋅競爭 ✅。🔴 鐵吸收抑制因子：(1) 咖啡 09:15（午餐前 2.75hr+），影響 15-20%（搭配 VitC 500mg 淨正效益）✅。(2) 綠茶 15:00（午餐後 3hr+），影響有限 ✅。(3) 植酸：午餐使用白米。(4) 草酸（菠菜）：僅影響自身鐵。主要鐵來源：牛肉、雞蛋、菠菜、雞肝 2×/週 50g。⚠️ 每半年驗血清鐵蛋白 Ferritin 目標 50-150 ng/mL', 'daily', '飲食', 31, true, '2026-03-01 06:47:56.430406+00', '2026-03-01 06:47:56.430406+00', 1),
	('f51d2393-a57c-482f-9d8e-076f27ba05eb', '全天 鈣攝取確認（目標 1000mg）', '每日確認鈣攝取是否達標 1000mg。主要來源：🥛 希臘優格 300g（~280mg 鈣，15:30 下午點心時段食用——距午餐鐵 3.5hr、距晚餐鐵 3.5hr，不影響鐵吸收）+ 深綠蔬菜（~150-200mg）。🔴 每日 17:00 服用鈣片 1 錠（+500mg）搭配小口柑橘類水果（碳酸鈣需胃酸溶解，空腹吸收率降低 30-40%，少量食物刺激胃酸分泌即可）——距 15:30 堅果鋅 1.5hr（鋅吸收完畢），距 19:00 晚餐鐵 2hr（鈣已離開腸道），距睡前鎂 5.5hr（無競爭）。板豆腐日：優格 280mg + 板豆腐 150-225mg + 鈣片 500mg + 蔬菜 150mg ≈ 1080-1155mg ✅。非板豆腐日：優格 280mg + 鈣片 500mg + 蔬菜 150mg + 酪蛋白 60-100mg ≈ 990-1080mg ✅', 'daily', '飲食', 25, true, '2026-02-27 11:16:20.633124+00', '2026-02-27 11:16:20.633124+00', 1),
	('b0fc52dd-1c6f-4282-8e5a-e5048e43b7a1', 'Ashwagandha 肝功能追蹤（第4/12週）', '⚠️ 開始服用新品牌 Ashwagandha 後，第 4 週及第 12 週各安排一次 ALT/AST 抽血。藥源性肝損傷多發於數週內，早期發現可避免惡化', 'daily', '補充品', 16, true, '2026-02-27 15:33:28.685695+00', '2026-02-27 15:33:28.685695+00', 1),
	('98c797e0-42a6-4855-9f95-ed9ed067bd93', '00:00 感恩練習', '睡前或早晨寫下三件感恩的事，調節自律神經系統', 'daily', '心理', 17, false, '2026-02-15 16:39:36.29248+00', '2026-02-15 16:39:36.29248+00', 1),
	('3c952729-5de1-4bfb-8a52-5c74fc518be2', '鋅 25mg 每日補充', '每日隨晚餐服用鋅 25mg（Zinc Picolinate 半顆）。與每日銅 2mg 維持 12.5:1 鋅銅比例，防止長期銅缺乏導致貧血與神經損傷。與 15:00 銅間隔 4hr+', 'daily', '補充品', 27, false, '2026-02-27 11:51:06.439264+00', '2026-02-27 11:51:06.439264+00', 1),
	('aa6005c2-8810-4be0-bc5f-403309bfac10', '15:30 下午點心', 'Tryall 豌豆蛋白 22g 粉（≈16g 蛋白）+ 雞蛋 1 顆（牛肉日從晚餐移入）+ 🥜 綜合堅果 45g + 南瓜籽 35g + 核桃 15g + 葵花籽 15g（共 110g）+ 🥛 希臘優格 300g（~280mg 鈣，此時段距午餐鐵 3.5hr、距晚餐鐵 3.5hr，鈣對正餐鐵吸收無影響）+ 🥥 椰子水 330ml（~600mg 鉀，每日必喝，鉀缺口核心補充）。💊 17:00 服用鈣片 1 錠（500mg）——距堅果鋅 1.5hr（DMT1 轉運完畢），距晚餐鐵 2hr（鈣已離開腸道）。⚠️ 堅果/種子全部集中於此時段：避免午餐/晚餐鋅（堅果 ~5.5mg）與鐵競爭 DMT1 轉運蛋白。⚠️ 訓練日本時段加 洋車前子殼 5g（見 F7），無脂溶性補充品不受影響。休息日可改為燕麥 80g + 藍莓 50g + 堅果種子 110g + 優格 + 椰子水。⚠️ 牛肉日：僅 1 顆蛋（6.3g 蛋白）+ 豌豆 16g = 22.3g', 'daily', '飲食', 11, true, '2026-02-27 10:53:40.044163+00', '2026-02-27 10:53:40.044163+00', 1),
	('40b5a986-3dcc-414d-b5d9-eb88bc48b202', '學習新技能', '樂器或語言學習最佳（結構性神經可塑性證據最強）。20-30 分鐘練習後安排運動，有助記憶鞏固。NSDR 也可在學習後使用', 'weekly', '心理', 4, true, '2026-02-15 16:39:36.62432+00', '2026-02-15 16:39:36.62432+00', 3),
	('67f57053-598c-4fa7-8c8d-7d8fa2f90a10', '全天 碳水循環：訓練日 vs 休息日', '重訓日 5-7g/kg (360-510g)、有氧日 3-4g/kg (215-290g)、休息日 3-3.5g/kg (220-255g)。重訓日熱量目標 3,100-3,400 kcal、休息日目標 2,400-2,600 kcal。🔴 休息日熱量控制：堅果種子從 110g 減至 75g（減少 ~200kcal 脂肪），或午餐橄欖油從 14g 減至 7g（減少 ~60kcal）。⚠️ 110g 堅果 + 42g 橄欖油 + 優格 + 正餐 = 休息日實際 ~2,800-3,000kcal，超出 200-400kcal。⚠️ 休息日碳水不可低於 3g/kg——低於此值造成每週熱量赤字（TDEE ~2,960 kcal/日），無法達成增肌目標 +0.5-1kg/月。⚠️ 高碳水日嚴格執行低纖維替換', 'daily', '飲食', 24, true, '2026-02-15 16:39:36.62432+00', '2026-02-15 16:39:36.62432+00', 1),
	('fe69c610-3716-4e11-8fbf-46d4935eae74', '每週回顧與調整', '記錄：1.早晨精神狀態 2.下午能量水平 3.運動後恢復速度 4.體重 7 日均值（目標每月 +0.5-1kg）5.主要複合動作進步。異常時優先調整睡眠與熱量', 'weekly', '一般', 5, false, '2026-02-15 16:39:36.62432+00', '2026-02-15 16:39:36.62432+00', 1),
	('c7bb8474-6b13-4ee4-8eb9-6c62d2a1921a', '09:45 穩定性訓練暖身', 'RAMP 暖身含穩定性訓練共 15 分鐘（升溫→激活→活動度→增強）：反伸展、反旋轉、單腳 RDL、肩胛穩定、抗側屈（行李箱負重走）', 'daily', '運動', 4, true, '2026-02-15 16:39:36.62432+00', '2026-02-15 16:39:36.62432+00', 1),
	('574e8f1a-521c-4599-8b56-3c30ebb92b5f', 'Quercetin + Fisetin 抗氧化抗發炎', '每週集中 2-3 天服用，抗氧化與抗發炎，輔助清除衰老細胞', 'weekly', '補充品', 5, false, '2026-02-15 16:39:36.62432+00', '2026-02-15 16:39:36.62432+00', 1),
	('f0e5aa63-105b-40b1-a025-74d20244863e', '鋅 25mg 補充', '每週 1-2 次服用鋅 25mg（Zinc Picolinate 半顆），建議週二、週六隨晚餐服用。與銅間隔 4hr+。降低長期高劑量風險，維持鋅銅比 10-15:1', 'weekly', '補充品', 12, false, '2026-02-27 10:53:40.044163+00', '2026-02-27 10:53:40.044163+00', 2),
	('a79de8f6-764b-4e42-9eda-e15b8784cbcd', '午餐 花椰菜烹調法（促甲狀腺物質管理）', '新鮮花椰菜含有硫化物（含促甲狀腺激素物質），當碘攝取邊界性不足時，這些物質會干擾碘吸收至甲狀腺。⚠️ 補救方案：
(1) 烹調時沸騰 10-15 分鐘 — 減少硫化物 40-60%（vs 生食或快炒）
(2) 與碘補充劑間隔 4+ 小時 — 建議花椰菜午餐（不含碘補），碘補隨早餐或晚餐
(3) 現在已補碘（NOW Foods 75mcg），風險已大幅降低（107-151mcg vs RDA 150mcg）
INSERT INTO "public"."products" ("id", "name", "description", "usage", "price", "url", "store", "category", "brand", "image_url", "rating", "review_count", "sku", "origin", "specs", "nutrition", "sort_order", "is_active", "created_at", "updated_at", "purchase_note") VALUES
	('a570f1a3-091b-4aa0-b9b7-f18666454036', '膠原蛋白肽 CollagenUP（CGN 206g）', '水解海洋膠原蛋白肽 + 玻尿酸 + 維他命 C（每 6.5g 含 80mg Vit C）。午餐服用 10-15g 已提供 ~120-160mg Vit C，為每日主要 Vit C 來源（搭配檸檬汁與蔬菜已遠超 RDA 100mg）。每日隨午餐服用', '每日 10-15g 隨午餐（已含 Vit C ~160mg）', 'NT$1,279 / 206g', 'https://tw.iherb.com/pr/california-gold-nutrition-collagenup-marine-hydrolyzed-collagen-hyaluronic-acid-vitamin-c-unflavored-7-26-oz-206-g/64903', 'iHerb', 'iherb_supplement', 'California Gold Nutrition', 'https://cloudinary.images-iherb.com/image/upload/f_auto,q_auto:eco/images/cgn/cgn01033/g/255.jpg', 4.7, NULL, 'CGN-01033', NULL, '{"form": "無調味粉末", "weight": "206g", "ingredients": "水解海洋膠原蛋白肽、玻尿酸、維他命C"}', '{"vitamin_c": "80mg", "serving_size": "6.5g", "hyaluronic_acid": "18mg", "collagen_peptides": "5.1g"}', 30, true, '2026-02-25 12:20:10.271551+00', '2026-02-25 12:20:10.271551+00', 'iHerb 直送。每日 10-15g，206g 約可用 2-3 週。搭配其他 iHerb 品項湊免運。'),
	('90e1787a-3791-45fa-847d-e87768f99056', '黑巧克力 85%+（Kirkland / Lindt）', '銅質主力來源（每 20g 含 ~0.5mg 銅）。搭配堅果+可可粉確保每日飲食銅 ≥0.9mg RDA，防止長期鋅補充導致銅缺乏。另含鎂（~50mg/20g）、鐵、多酚抗氧化物。選 85% 以上可可含量，糖分極低', '每日 20g（必須，作為銅來源）', 'NT$200-400 / 100g', 'https://www.costco.com.tw/Food-Dining/Snacks/Chocolate/c/90506', 'Costco / 全聯', 'costco_food', 'Kirkland / Lindt', NULL, NULL, NULL, NULL, '瑞士/比利時', '{"cocoa": "85%以上", "storage": "陰涼避光處，勿冷藏（會出霜影響口感）"}', '{"iron_per_20g": "~2.4mg", "copper_per_20g": "~0.5mg", "calories_per_20g": "~120kcal", "magnesium_per_20g": "~50mg"}', 19, true, '2026-03-01 06:03:29.532199+00', '2026-03-01 06:03:29.532199+00', '每日 20g（必須，非零食而是銅來源）。Costco Kirkland 72% 巧克力餅乾不適用（可可含量太低）。選 Lindt Excellence 85% 或 90%（全聯/家樂福約 NT$120-150/100g）。100g 可用 5 天。'),
	('8008edd1-701b-428f-8163-c3ad7a4287ba', '緩釋魚油（Kirkland 新型緩釋 Omega-3）', '每 1200mg 魚油含 Omega-3 約 700mg（EPA 419mg + DHA 281mg）。沙丁魚、鯷魚、鯖魚來源，緩釋不打嗝。產地加拿大。🔴 從 3 顆降至 2 顆/日——EPA+DHA 1400mg 已覆蓋心血管保護與抗發炎效益（VITAL 試驗支持 840mg+），>2000mg/日額外效益有限但出血風險增加', '每日隨餐 2 顆（EPA+DHA 共 1400mg）。⚠️ 鮭魚日減為 1 顆（700mg + 鮭魚 ~1200mg ≈ 1900mg）。從 3 顆降至 2 顆——EPA+DHA 效益在 1500-2000mg 趨於平穩，>2000mg 增加 LDL 氧化與出血風險', 'NT$579 / 180 顆', 'https://www.costco.com.tw/Health-Beauty/Supplements/Supplements-Digestive-Support/Kirkland-Signature-Enteric-Omega-3-Fish-Oil-180-Softgel/p/240669', 'Costco', 'costco_supplement', 'Kirkland Signature 科克蘭', NULL, NULL, NULL, NULL, '加拿大', '{"form": "軟膠囊", "count": "180粒", "storage": "請置於陰涼乾燥處，開瓶後請旋緊瓶蓋，並避免陽光直射。", "allergens": "本產品含魚可能導致過敏症狀。不添加乳糖、人工色素及麩質。", "ingredients": "魚油(沙丁魚、鯷魚、鯖魚)、明膠(豬來源)、甘油、水、柑橘果膠、D-山梨醇(甜味劑)"}', '{"dha": "281毫克", "epa": "419毫克", "per_serving": "每1200毫克濃縮魚油", "omega3_total": "約700毫克"}', 1, true, '2026-02-17 15:37:55.858395+00', '2026-02-17 15:37:55.858395+00', '線上可訂（常溫配送）。每日 2 顆，180 顆可用 3 個月。⚠️ 開瓶後必須冷藏（2-8°C），每次取用後迅速旋緊瓶蓋。📋 在瓶身標註開瓶日期，開瓶後 60 天內用完。⚠️ 有腥味或苦味表示已氧化變質，立即丟棄。'),
	('ae0c2a1d-87f3-47ed-a86f-af03fe9dd51c', '板豆腐（傳統硬豆腐）', '優質植物蛋白 + 鈣質來源。100g 板豆腐含鈣 ~150mg + 蛋白質 ~8g。大豆製品含植酸，但午餐食用後經 7hr 消化（胃排空 2-4hr + 小腸轉運 3-5hr），植酸已進入大腸，不影響 19:00 晚餐鋅吸收（鋅主要在十二指腸與空腸吸收）。⚠️ 晚餐碳水仍應避開全穀類（糙米、燕麥）：同餐植酸才是鋅吸收的真正干擾源', '每週 2-3 次午餐入菜（100-150g），晚間正常補鋅', 'NT$15-30 / 塊', 'https://www.pxmart.com.tw', '全聯 / 傳統市場 / 便利商店', 'convenience_daily', NULL, NULL, NULL, NULL, NULL, '台灣', '{"portion": "每次 100-150g", "storage": "冷藏 3-5 天，開封後浸水每日換水", "varieties": "板豆腐（硬，適合煎炒）、嫩豆腐（軟，適合湯品）"}', '{"per_100g": "76kcal, 蛋白質 8.1g, 鈣 150mg, 鐵 1.5mg, 脂肪 4.8g"}', 18, true, '2026-02-27 19:43:28.137356+00', '2026-02-27 19:43:28.137356+00', '每週補貨 2-3 次（保質期短）。'),
	('5260884e-9e06-4348-bd9c-5a444632a89f', '洋蔥 / 大蒜', '膳食纖維與益生元（菊糖 Inulin）來源', '日常入菜', '~NT$149', 'https://www.costco.com.tw/Food-Dining/Frozen-Fresh-Food/Chilled-Fresh-Food/c/90901', 'Costco', 'costco_food', NULL, NULL, NULL, NULL, NULL, NULL, '{}', '{}', 8, true, '2026-02-17 15:37:55.858395+00', '2026-02-17 15:37:55.858395+00', '賣場蔬果區散裝。常溫通風處可保存 2-4 週，耗量低，每月補一次即可。'),
	('3bbc5601-172c-4829-83e5-2dd7e084c92f', '鋅 Zinc Picolinate（NOW Foods 15mg × 120 錠）', '⛔ 已停用（2026-03-01 營養審查）。飲食鋅已達 10-15mg/日（雞蛋 ~5mg + 肉類 ~5-12mg + 堅果 ~2-3mg），超過 RDA 11mg。額外補充 15mg 使總計達 25-30mg（接近 UL 40mg），鋅銅比過高。⚠️ 每半年驗血清鋅，若 <70mcg/dL 才考慮恢復補充。保留產品供參考', '⛔ 已停用。飲食鋅已達 RDA 11mg，無需額外補充', 'NT$250-350 / 120 錠', 'https://tw.iherb.com/pr/now-foods-zinc-picolinate-30-mg-100-veg-capsules/733', 'iHerb', 'iherb_supplement', 'NOW Foods', 'https://cloudinary.images-iherb.com/image/upload/f_auto,q_auto:eco/images/now/now01552/g/57.jpg', 4.8, 46833, 'NOW-01552', NULL, '{"form": "錠劑", "count": "120錠", "chelate_type": "吡啶甲酸鋅"}', '{"zinc": "15mg", "serving_size": "1錠"}', 25, false, '2026-02-17 15:37:55.858395+00', '2026-02-17 15:37:55.858395+00', 'iHerb 直送。✅ 15mg 錠劑（非 50mg 膠囊），可精確控量。每日 1 錠，120 錠可用 4 個月。'),
	('d42bb558-3cd6-471d-86a5-6b6de10d5ef7', '牙線（Oral-B / GUM / 3M）', '口腔衛生必需品。牙周病菌（P. gingivalis）與心血管疾病、阿茲海默症強相關。牙刷僅清潔 60% 牙面，牙線覆蓋剩餘 40% 齒縫', '每日至少 1 次（睡前刷牙後）', 'NT$50-150 / 盒', 'https://www.costco.com.tw/Health-Beauty/Oral-Care/Dental-Floss/c/90401', 'Costco / 全聯 / 便利商店', 'personal_care', NULL, NULL, NULL, NULL, NULL, NULL, '{}', '{}', 42, true, '2026-02-27 19:43:28.137356+00', '2026-02-27 19:43:28.137356+00', '每 2-3 個月購買 1 盒。Costco 有大包裝（3 入組更划算）。建議選含蠟牙線（滑順不易卡牙縫）。'),
	('c77a95bb-279e-4ba3-9e8a-fe5651246fd9', '洋車前子殼粉（NOW Foods Psyllium Husk Powder 340g）', '天然水溶性膳食纖維，吸水膨脹形成凝膠促進腸道蠕動。訓練日纖維補充主力，每 5g 含 ~4g 膳食纖維。⚠️ 增量至 8-10g/次（6.4-8g 纖維），搭配 350ml+ 水', '訓練日 09:15 5g + 午餐前 5g，各沖 250ml 水', 'NT$250-350 / 340g', 'https://tw.iherb.com/pr/now-foods-psyllium-husk-powder-12-oz-340-g/1041', 'iHerb', 'iherb_supplement', 'NOW Foods', NULL, NULL, NULL, NULL, NULL, '{"form": "粉末", "weight": "340g", "ingredients": "洋車前子殼粉"}', '{"serving_size": "5g", "dietary_fiber": "~4g", "soluble_fiber": "~3g"}', 39, true, '2026-03-01 06:18:05.208027+00', '2026-03-01 06:18:05.208027+00', 'iHerb 直送。訓練日使用（每週 4-5 天），340g 約可用 2-3 個月。⚠️ 沖泡後立即飲用（放置會凝固成膠狀難以吞嚥）。搭配 250ml+ 水，避免腸阻塞。'),
	('b4e8e0a7-6021-4bde-bb66-79f394fae071', '蜂蜜 / 無糖可可粉', '豌豆蛋白調味用。無調味豌豆蛋白口感較澀，少量蜂蜜或可可粉可大幅提升適口性與遵從性', '15:30 下午點心搭配豌豆蛋白使用', 'NT$100-300', 'https://www.costco.com.tw/Food-Dining/Pantry/Honey-Sweeteners/c/90301', 'Costco / 全聯', 'convenience_daily', NULL, NULL, NULL, NULL, NULL, NULL, '{"蜂蜜": "每次 5-10g（~15-30kcal），選台灣產龍眼蜜或百花蜜", "可可粉": "每次 5g，選無糖純可可粉（如 Hersheys Unsweetened）"}', '{"蜂蜜_per_10g": "30kcal, 碳水 8g", "可可粉_per_5g": "10kcal, 膳食纖維 1.7g, 鎂 25mg"}', 19, true, '2026-02-27 19:43:28.137356+00', '2026-02-27 19:43:28.137356+00', '蜂蜜常溫保存（永不過期）；可可粉開封後密封保存 6 個月。每日用量極少（5-10g），一罐可用數月。'),
	('fa985ab4-603c-41ed-90e8-8324936d5003', '維他命 C（NOW Foods 500mg × 100 錠）', '每日 Vit C 補充。🔴 分時服用最大化吸收：午餐 1 錠（500mg，搭配鐵質食物促進吸收 2-6 倍）+ 晚餐半錠（250mg，覆蓋晚餐鐵吸收需求）。膠原蛋白日午餐已含 VitC 120-160mg，仍建議服用 1 錠以確保鐵吸收最佳化。⚠️ 切半錠備晚餐用——500mg 錠劑用切藥器對半切開，半錠隨晚餐服用。Vit C 半衰期 ~2hr，分次服用維持血中濃度', '午餐 1 錠（500mg）+ 晚餐半錠（250mg）。每日共 750mg，分 2 次服用', 'NT$250-350 / 100 錠', 'https://tw.iherb.com/pr/now-foods-c-500-100-tablets/690', 'iHerb', 'iherb_supplement', 'NOW Foods', NULL, NULL, NULL, NULL, '加拿大', '{"form": "錠劑", "count": "100錠", "storage": "請存放於乾燥陰涼處，開封後請旋緊瓶蓋。", "ingredients": "抗壞血酸(維生素C)"}', '{"vitamin_c": "500mg/錠"}', 3, true, '2026-02-17 15:37:55.858395+00', '2026-02-17 15:37:55.858395+00', 'iHerb 直送。✅ 每日 1 錠（500mg），免切免切藥器。100 錠可用約 3 個月。開瓶後標記日期，6 個月內用完。'),
	('c2987259-07c3-4abc-9a77-a8aced36e750', '甘胺酸鎂 Mg Glycinate（NOW Foods 100mg × 180 錠）', '甘胺酸是抑制性神經傳導物質，降低核心體溫助眠。高吸收率', '睡前 1.5 錠（150mg）。與蘇糖酸鎂 144mg（15:00 服用）合計補充品鎂 294mg，安全低於 UL 350mg', 'NT$399 / 180 錠', 'https://tw.iherb.com/pr/now-foods-magnesium-glycinate-180-tablets-100-mg-per-tablet/88819', 'iHerb', 'iherb_supplement', 'NOW Foods', 'https://cloudinary.images-iherb.com/image/upload/f_auto,q_auto:eco/images/now/now01289/g/41.jpg', 4.8, 30061, 'NOW-01289', NULL, '{"form": "錠劑", "count": "180錠", "chelate_type": "TRAACS™ 甘氨酸鎂"}', '{"magnesium": "150mg（提取自1500mg甘氨酸鎂）", "serving_size": "1.5錠"}', 23, true, '2026-02-17 15:37:55.858395+00', '2026-02-17 15:37:55.858395+00', 'iHerb 直送。每日 1.5 錠（150mg），180 錠可用 4 個月。與蘇糖酸鎂（每月補貨）合併 iHerb 訂購節省運費。'),
	('a57c14c9-9312-4ef4-a171-7a1dbcaf968f', '酪梨', '修復鉀缺口（每顆 ~700mg 鉀）+ 健康單元不飽和脂肪 + 膳食纖維 7g。⚠️ 每日必須食用半顆至一顆，不可省略——鉀是全計畫最大缺口（AI 3400mg vs 現行 ~2500-3000mg）', '每日半顆至一顆（必須）', '~NT$329 / 1.3kg', 'https://www.costco.com.tw/Food-Dining/Frozen-Fresh-Food/Chilled-Fresh-Food/c/90901', 'Costco', 'costco_food', NULL, NULL, NULL, NULL, NULL, NULL, '{}', '{}', 14, true, '2026-02-17 15:37:55.858395+00', '2026-02-17 15:37:55.858395+00', '賣場蔬果區散裝。輕捏微軟代表已熟。未熟室溫放 2-3 天催熟。1.3kg 約 4-5 顆，4-7 天用完。'),
	('72fa6080-74b0-4b44-af07-a23818dbdb91', '大白菜 / 高麗菜 / 小白菜', '低草酸、低植酸葉菜，晚餐首選（不干擾鋅吸收）。富含維他命 C、K、鉀、膳食纖維。大白菜草酸僅 ~20mg/100g（菠菜 ~750mg/100g 的 1/37）', '晚餐蔬菜首選（搭配鋅服用日），午餐可搭配高草酸蔬菜（有鈣保護）', 'NT$20-50 / 顆或把', 'https://www.pxmart.com.tw', '傳統市場 / 全聯 / 頂好', 'costco_food', NULL, NULL, NULL, NULL, NULL, '台灣', '{"storage": "冷藏 3-5 天", "varieties": "大白菜（整顆較大，切半使用）、高麗菜（耐儲存 5-7 天）、小白菜（保存期短 2-3 天）"}', '{"per_100g": "大白菜 13kcal, 蛋白質 1.1g, 鉀 176mg, 草酸 ~20mg；高麗菜 25kcal, 蛋白質 1.3g；小白菜 13kcal, 蛋白質 1.5g, 鈣 105mg"}', 16, true, '2026-02-27 18:27:45.758052+00', '2026-02-27 18:27:45.758052+00', '每週補貨 1-2 次。高麗菜最耐儲存（5-7 天），大白菜次之（3-5 天切半保鮮膜包），小白菜最短（2-3 天墊廚房紙巾）。'),
	('c6de100d-9ab3-44cf-b358-2a9f9cc46957', '泡菜（宗家府 冷藏切塊泡菜 120g×6）', '韓國產冷藏泡菜，活性乳酸菌來源。成分含白菜、蘿蔔、辣椒、大蒜、韭菜、蝦醬、鯷魚醬。賣場限定商品', '每日 ≤30g 隨餐（控鈉：100g 泡菜含鈉 ~600-900mg，30g 約 180-270mg）', '~NT$259 / 120g×6', 'https://www.costco.com.tw/Warehouse-Only/Food-Beverages/Chilled/JONGGA-Sliced-Kimchi-120-g-X-6-Pack/p/137728', 'Costco', 'costco_food', '宗家府', NULL, NULL, NULL, NULL, '韓國', '{"count": "120公克 X 6入", "weight": "720公克", "storage": "0°C-7°C", "allergens": "本產品含有魚,蝦類及其製品,不適合其過敏體質者食用.", "ingredients": "白菜,蘿蔔,米澱粉,辣椒,大蒜,韭菜,果糖,昆布萃取物,鹽,大蔥,鰹魚萃取物,梨,鯷魚醬(鯷魚,鹽),蝦醬(蝦,鹽,鯷魚,玉米糖膠),甜味劑(D-山梨醇,麥芽糖醇),L-麩酸鈉", "warehouse_only": true}', '{}', 13, true, '2026-02-17 15:37:55.858395+00', '2026-02-23 09:10:23.687281+00', '賣場限定，無法線上訂。每日 ≤30g（控鈉），120g×6 約 24 天，每月補貨 1 次即可。小圓罐適合見縫插針：兩兩疊放在優格罐前方，或利用層板間的零碎高度。⚠️ 泡菜為高鈉食物，嚴格限量 30g/日以配合 WHO <2400mg/日鈉攝取目標'),
	('4e08480d-ba23-4306-99f1-66afab522817', '冷凍草飼牛肉片（澳洲）', '紅肉提供血基質鐵（吸收率 15-35%）、維他命 B12、天然肌酸。草飼牛肉 Omega-3 較高', '每週 1-2 次晚餐（嚴格上限 150g/次），牛肉日雞蛋分散至午餐（1-2 顆）與下午點心（1 顆）', 'NT$600-800 / 1kg', 'https://www.costco.com.tw/Food-Dining/Frozen-Fresh-Food/Frozen-Seafood-Meat/c/90701', 'Costco', 'costco_food', NULL, NULL, NULL, NULL, NULL, '澳洲', '{"cut": "薄片火鍋肉片或牛排", "fat": "選擇瘦部位（如菲力、後腿）", "storage": "冷凍 -18°C"}', '{"b12": "豐富", "iron": "2-3mg（血基質鐵）", "creatine": "天然含有", "protein_per_100g": "20-25g"}', 23, true, '2026-02-26 14:43:42.995593+00', '2026-02-26 14:43:42.995593+00', '每週 1-2 次作為紅肉來源（嚴格上限 150g/次）。牛肉日雞蛋分散至午餐與下午點心。草飼優於穀飼。瘦部位脂肪 <10g/100g。'),
	('4c3d3580-1140-483d-90cf-8e178085f3d5', '冷凍鮭魚排（Kirkland 1.36kg）', '挪威養殖大西洋鮭魚，優質蛋白 + Omega-3 來源。成分：鮭魚、水、食鹽', '每週 3-4 份', 'NT$1,229 / 1.36kg', 'https://www.costco.com.tw/Food-Dining/Frozen-Fresh-Food/Frozen-Seafood-Meat/Kirkland-Signature-Frozen-Atlantic-Salmon-136-kg/p/1286092', 'Costco', 'costco_food', 'Kirkland Signature 科克蘭', NULL, NULL, NULL, NULL, '挪威', '{"weight": "1.36公斤", "cooking": "烤：將烤箱預熱至200℃，將解凍後的鮭魚調味後放在烤盤上烤約10-12分，或直到中心溫度達63℃。", "storage": "請冷凍-18℃保存。", "allergens": "本產品含有鮭魚，食物過敏者，請注意。", "ingredients": "養殖鮭魚、水、食鹽"}', '{}', 5, true, '2026-02-17 15:37:55.858395+00', '2026-02-23 09:10:23.687281+00', '冷凍庫主力，每 2 週線上訂 1 包（冷凍配送）。買回立即分裝 5-6 份 zip bag（佔冷凍約 2.5L），每 2-3 天取 1 份移至冷藏解凍。冷凍庫僅 7L，鮭魚是唯一大型需要長期冷凍的食材（藍莓等小包裝另計）。'),
	('2230968a-32ef-4344-9ab9-cf95b3179123', 'L-Theanine（NOW Foods Double Strength 200mg × 120 顆）', '搭配咖啡的最強 nootropic 組合（A 級證據）。促進專注 + 放鬆，消除咖啡因焦慮感。120 顆大包裝更划算', '每日 1 顆（200mg）09:15 隨咖啡服用。下午綠茶另含天然 L-Theanine 40-90mg 為額外紅利', 'NT$399 / 120 顆', 'https://tw.iherb.com/pr/now-foods-double-strength-l-theanine-200-mg-120-veg-capsules/54096', 'iHerb', 'iherb_supplement', 'NOW Foods', 'https://cloudinary.images-iherb.com/image/upload/f_auto,q_auto:eco/images/now/now00148/g/32.jpg', 4.7, 16952, 'NOW-00148', NULL, '{"form": "素食膠囊", "count": "120顆"}', '{"l_theanine": "200mg", "serving_size": "1顆"}', 29, true, '2026-02-17 15:37:55.858395+00', '2026-02-17 15:37:55.858395+00', 'iHerb 直送。Double Strength 200mg 素食膠囊。60 顆約可用 2 個月。搭配其他 iHerb 品項湊免運。'),
	('7b2ee619-ad9a-4b7d-98ce-4aab1cb2773d', '地瓜', '原型碳水來源 + 維他命A主力（橘色品種）。訓練前能量補充（前晚蒸好冷藏 → RS3）。冷卻後產生抗性澱粉（益生元）。⚠️ 必選台農 57 號等橘色品種：每 100g 含 ~700mcg RAE β-胡蘿蔔素，是全計畫唯一高效維他命A來源。白肉/紫肉地瓜β-胡蘿蔔素極低，不可替代。非重訓日晚餐可食用（色氨酸→血清素→褪黑激素，助眠）。⚠️ 重訓日晚餐禁用冷卻地瓜（RS 發酵 + 睡前甘胺酸鎂 → 夜間腹脹）', '訓練前 1 次（新鮮/熱食，不冷藏）+ 訓練後或休息日晚餐（冷藏 RS3 版本）', '~NT$135 / 2.8kg', 'https://www.costco.com.tw/Food-Dining/Frozen-Fresh-Food/Chilled-Fresh-Food/c/90901', 'Costco', 'costco_food', NULL, NULL, NULL, NULL, NULL, NULL, '{}', '{}', 7, true, '2026-02-17 15:37:55.858395+00', '2026-02-17 15:37:55.858395+00', '賣場蔬果區散裝。挑外皮光滑無發芽。每週約 1 袋（2.8kg）。常溫陰涼處可放 1-2 週，勿冷藏（冷藏會產生 RS3，不適合訓練前使用）。若要產生 RS3 用於訓練後食用，需單獨蒸熟後冷藏，與鮮食備份分開保存。'),
	('bb4ff53e-16c0-44ea-97b1-8ae7300055be', '檸檬', '早晨補水，促進消化', '每日半顆', '~NT$329 / 2.2kg', 'https://www.costco.com.tw/Food-Dining/Frozen-Fresh-Food/Chilled-Fresh-Food/c/90901', 'Costco', 'costco_food', NULL, NULL, NULL, NULL, NULL, NULL, '{}', '{}', 10, true, '2026-02-17 15:37:55.858395+00', '2026-02-23 09:10:23.687281+00', '賣場蔬果區散裝。選外皮鮮黃有光澤。整顆放保鮮抽屜，切半後用矽膠套包住切面冷藏。每日半顆，約可用 3-4 週。'),
	('fd5ff884-6484-4bcc-b185-acde9de6b8bf', '新鮮綠花椰菜（傳統市場/超市）', '十字花科蔬菜，富含蘿蔔硫素 Sulforaphane（Nrf2 激活劑）。切碎後靜置 40 分鐘可最大化黑芥子酶轉化。⚠️ 備餐時間軸：09:00 起床時立刻切碎放入保鮮盒冷藏（訓練期間完成 40 分鐘靜置），午餐直接取出烹調。或改用於 19:00 晚餐（時間彈性較大，運動後有充足備餐時間）', '每日一份', 'NT$20-30 / 顆', 'https://www.pxmart.com.tw', '傳統市場 / 全聯 / 頂好', 'costco_food', 'Nature''s Touch', NULL, NULL, NULL, NULL, '厄瓜多', '{"portion": "每次2-3顆", "storage": "冷藏3-4天", "preparation": "切碎靜置40分鐘最大化蘿蔔硫素"}', '{}', 6, true, '2026-02-17 15:37:55.858395+00', '2026-02-23 09:10:23.687281+00', '每週補貨 2 次，每次買 3-4 顆（每顆約 300-400g）。裝入有瀝水網底的長方形保鮮盒，冷藏可放 3-4 天。小冰箱用戶不建議買 Costco 冷凍版（454g×4 佔冷凍 3L 直接爆倉）。📋 每日 09:00 起床時先切碎放保鮮盒冷藏，訓練結束後可直接烹調（已完成 40 分鐘蘿蔔硫素轉化）'),
	('447b150f-502d-438e-b74c-f6337fb60bb1', '蘇糖酸鎂 Magtein（NOW Foods 90 顆）', '唯一可穿越血腦屏障的鎂型態（鎂 L-蘇糖酸鹽）。改善認知功能與睡眠品質', '每日 3 顆（元素鎂 ~144mg），14:00 空腹服用（午餐後 2hr）。⚠️ 不可與 15:00 綠茶同服——EGCG 螯合 Mg²⁺ 降低吸收率。距 17:00 鈣片 3hr，無競爭', 'NT$874 / 90 顆', 'https://tw.iherb.com/pr/now-foods-magtein-magnesium-l-threonate-90-veg-capsules/57577', 'iHerb', 'iherb_supplement', 'NOW Foods', 'https://cloudinary.images-iherb.com/image/upload/f_auto,q_auto:eco/images/now/now02390/g/50.jpg', 4.8, NULL, 'NOW-02390', NULL, '{"form": "素食膠囊", "count": "90顆"}', '{"serving_size": "3顆", "elemental_magnesium": "144mg", "magnesium_l_threonate": "2000mg"}', 35, true, '2026-02-25 15:46:19.988974+00', '2026-02-25 15:46:19.988974+00', 'iHerb 直送。每日 3 顆，90 顆僅可用 30 天（⚠️ 每月必須補貨）。建議與甘胺酸鎂（180 錠/3 個月）合併訂購以節省運費：每 3 個月訂 3 罐蘇糖酸鎂 + 1 罐甘胺酸鎂。'),
	('399a8292-409b-402f-b4d0-1c2680d7fecf', '新鮮菠菜（傳統市場/超市）', '低 FODMAP 蔬菜，鉀、鎂、鐵、葉酸來源。搭配維他命C增強鐵吸收', '每日 100-150g 入菜', 'NT$30-50 / 300-400g', 'https://www.pxmart.com.tw', '傳統市場 / 全聯 / 頂好', 'costco_food', NULL, NULL, NULL, NULL, NULL, NULL, '{"portion": "每週300-400g", "storage": "冷藏3-5天", "preparation": "墊廚房紙巾吸濕"}', '{}', 15, true, '2026-02-17 15:37:55.858395+00', '2026-02-23 09:10:23.687281+00', '每週補貨 2 次，每次買 400-500g。放入大保鮮袋、裡面墊一張廚房紙巾吸濕，平放於保鮮抽屜底部，3-5 天內用完。小冰箱用戶不建議買 Costco 冷凍版（500g×6 佔冷凍室 70%）'),
	('f7475193-f956-4055-b150-efb5278ba0f8', '葉黃素 + 玉米黃素（CGN 20mg × 120 顆）', '沉積於視網膜黃斑部，保護眼睛抵禦藍光與氧化傷害。📋 每季評估必要性：23 歲無黃斑部病變家族史者，風險極低。若無高度近視或長時間螢幕工作，可考慮停用以減少補充品總量。若繼續服用，建議移至晚餐（避免午餐脂溶性競爭）', '每日 1 顆隨餐（需搭配油脂吸收）', 'NT$914 / 120 顆', 'https://tw.iherb.com/pr/california-gold-nutrition-lutein-with-zeaxanthin-from-marigold-extract-120-veggie-softgels/94824', 'iHerb', 'iherb_supplement', 'California Gold Nutrition', 'https://cloudinary.images-iherb.com/image/upload/f_auto,q_auto:eco/images/cgn/cgn01403/g/126.jpg', 4.7, 45894, 'CGN-01403', NULL, '{"form": "素食軟膠囊", "count": "120顆", "source": "mGold™ 萬壽菊花提取物", "ingredients": "葉黃素（來自萬壽菊提取物）（花）、玉米黃質（來自萬壽菊提取物）（花）"}', '{"lutein": "20mg", "zeaxanthin": "含玉米黃質", "serving_size": "1顆"}', 24, true, '2026-02-17 15:37:55.858395+00', '2026-02-17 15:37:55.858395+00', 'iHerb 直送。每日 1 顆，120 顆可用 4 個月。CGN 自有品牌 CP 值高。'),
	('48534f47-5bab-4aad-b2ff-a2feffe11bf3', '卵磷脂顆粒（NOW Foods Sunflower Lecithin 454g）', '向日葵卵磷脂（非大豆），富含磷脂醯膽鹼（Phosphatidylcholine）。牛肉日膽鹼補充主力，每大匙（~10g）含 ~120mg 膽鹼。牛肉日用 1.5 大匙（~180mg 膽鹼）確保達 AI 550mg。非基改、無大豆過敏風險', '牛肉日 1.5 大匙（~15g, ~180mg 膽鹼）隨餐。豆腐日或低膽鹼蛋白日（雞蛋 <4 顆且非雞肉/鮭魚）1 大匙（~10g, ~120mg 膽鹼）。或每日加入燕麥/優格', 'NT$400-500 / 454g', 'https://tw.iherb.com/pr/now-foods-sunflower-lecithin-pure-powder-1-lb-454-g/72188', 'iHerb', 'iherb_supplement', 'NOW Foods', NULL, NULL, NULL, NULL, NULL, '{"form": "顆粒粉末", "weight": "454g", "features": "非基改、無大豆", "ingredients": "向日葵卵磷脂"}', '{"choline": "~120mg", "serving_size": "10g (1大匙)", "phosphatidylcholine": "~1200mg"}', 38, true, '2026-03-01 06:18:05.208027+00', '2026-03-01 06:18:05.208027+00', 'iHerb 直送。454g 約 45 份。牛肉日必用（每週 1-2 次），非牛肉日可選用。顆粒可直接拌入燕麥碗或優格，口感中性。常溫保存。'),
	('6d60bdd6-ea74-4911-9984-37caa5f03cb0', '香蕉', '訓練前後快速碳水，富含鉀。青香蕉含抗性澱粉（益生元）', '每日 1-2 根（訓練前後）', '~NT$99 / 1.4kg', 'https://www.costco.com.tw/Food-Dining/Frozen-Fresh-Food/Chilled-Fresh-Food/c/90901', 'Costco', 'costco_food', NULL, NULL, NULL, NULL, NULL, NULL, '{}', '{}', 18, true, '2026-02-17 15:37:55.858395+00', '2026-02-17 15:37:55.858395+00', '賣場蔬果區散裝。選微青帶黃放 2-3 天自然熟成。1.4kg 約 7-8 根，4-7 天用完。'),
	('525a8b9b-b879-48c3-9619-5cb58aeede7d', '有機糙米（銀川有機一等糙米 3kg）', '花蓮產有機糙米。基礎碳水來源，冷卻後產生抗性澱粉（益生元）。提供膳食纖維與鎂', '每日適量，訓練日增加碳水攝取', 'NT$359 / 3kg', 'https://www.costco.com.tw/Food-Dining/Groceries/Rice-Noodles/Greenme-Organic-Brown-Rice-3-kg/p/124095', 'Costco', 'costco_food', '銀川', NULL, NULL, NULL, NULL, '台灣（花蓮）', '{"weight": "3公斤", "ingredients": "有機糙米"}', '{}', 20, true, '2026-02-17 15:37:55.858395+00', '2026-02-17 15:37:55.858395+00', '線上可訂（常溫配送）。3kg 約 3-6 週。有機花蓮產。開封後密封避免蟲害，夏天建議冷藏。'),
	('91d10e93-4790-48d4-8d73-c696996e375c', '甘胺酸 Glycine Pure Powder（NOW Foods 454g）', '抑制性神經傳導物質，降低核心體溫促進深層睡眠。參與膠原蛋白合成與肌酸生成', '睡前 3g（約半茶匙）', 'NT$710 / 454g', 'https://tw.iherb.com/pr/now-foods-glycine-pure-powder-1-lb-454-g/615', 'iHerb', 'iherb_supplement', 'NOW Foods', 'https://cloudinary.images-iherb.com/image/upload/f_auto,q_auto:eco/images/now/now00225/g/32.jpg', 4.8, NULL, 'NOW-00225', NULL, '{"form": "純粉末", "weight": "454g", "ingredients": "甘胺酸"}', '{"glycine": "3g", "serving_size": "3g"}', 34, true, '2026-02-25 15:46:19.988974+00', '2026-02-25 15:46:19.988974+00', 'iHerb 直送。每日 3g，454g 可用 5 個月。微甜味，可直接加入豌豆蛋白一起沖泡。'),
	('f3829f9b-e08f-48b6-b6c7-9c92ba42e10b', '雞肝（傳統市場/超市）', '鐵質最強食物來源。每 100g 含血基質鐵 ~11mg（吸收率 25-35%）。另含維他命A（視黃醇形式）、B12、葉酸、銅。🔴 每週 2 次 50g（從 100g 減量——2×100g 週均維他命A ~3,140mcg RAE/日超 UL 3000mcg。2×50g = ~1,571mcg RAE/日，安全且仍覆蓋 BCMO1 poor converters 需求）。⚠️ 每週上限 100g 總量', '每週 2 次午餐入菜（每次 50g），替代當天其他動物蛋白。⚠️ 嚴格上限 2 次/週各 50g', 'NT$30-60 / 300g', 'https://www.pxmart.com.tw', '傳統市場 / 全聯', 'costco_food', NULL, NULL, NULL, NULL, NULL, '台灣', '{"storage": "冷藏 1-2 天，買回當天或隔天烹調", "preparation": "清水浸泡 30 分鐘去血水，汆燙後再炒"}', '{"per_100g": "119kcal, 蛋白質 16.9g, 鐵 11mg（血基質鐵）, 維他命A 11000mcg RAE, B12 16.6mcg, 葉酸 590mcg, 銅 0.5mg"}', 16, false, '2026-03-01 07:06:13.964256+00', '2026-03-01 07:06:13.964256+00', '每週買 1 次 100g 即可。傳統市場最新鮮。冷藏 1-2 天內烹調完畢。⚠️ 嚴格每週 1 次上限——維他命A（視黃醇）過量有肝毒性。'),
	('1ff182e0-9952-49c5-a834-99239c6e75c8', '食品電子秤', '精準測量蛋白粉、食材重量、每日碘鹽（0.1g 精度）。確保每日蛋白質及碘攝取達標', '每餐使用，精度 0.1-1g', 'NT$300~800', 'https://www.amazon.com/digital-kitchen-food-scale/s?k=digital+kitchen+food+scale', 'Amazon', 'equipment', NULL, NULL, NULL, NULL, NULL, NULL, '{}', '{}', 38, true, '2026-02-17 15:37:55.858395+00', '2026-02-17 15:37:55.858395+00', '一次性購買，Amazon 或蝦皮。精度 0.1g，最大秤量至少 5kg。$300-800 即可。⚠️ 碘鹽每日用量 3-5g 需精確測量（1/4 茶匙量勺誤差 40% 不可靠），電子秤為唯一可靠工具。'),
	('91abab3a-90b4-4229-85a6-993c78da68f4', '防藍光眼鏡（琥珀色鏡片）', '阻擋 400-550nm 藍光，保護褪黑激素分泌', '22:00 後佩戴', 'NT$500~1,500', 'https://www.amazon.com/amber-blue-light-blocking-glasses/s?k=amber+blue+light+blocking+glasses', 'Amazon', 'equipment', NULL, NULL, NULL, NULL, NULL, NULL, '{}', '{}', 37, true, '2026-02-17 15:37:55.858395+00', '2026-02-17 15:37:55.858395+00', '一次性購買，Amazon 或蝦皮。選琥珀色鏡片才有效阻擋藍光。$500-1,500 即可。'),
	('7619318d-79c0-48c3-a066-4ac981309ceb', '維他命 D3 1000IU（NOW Foods 180 顆）', '每日服用 2 顆（2000 IU）。Endocrine Society 建議 1500-2000 IU/日，目標血清 25(OH)D 40-60 ng/mL。血檢達標+每日晨光曝曬→可進一步減量。✅ 1000IU 軟凝膠，每日 2 顆', '每日 2 顆（2000 IU）隨訓練後餐（需搭配油脂吸收）', 'NT$300-400 / 180 顆', 'https://tw.iherb.com/pr/now-foods-vitamin-d-3-high-potency-1-000-iu-180-softgels/10421', 'iHerb', 'iherb_supplement', 'NOW Foods', NULL, 4.8, NULL, 'NOW-00375', NULL, '{"form": "軟凝膠", "count": "180顆"}', '{"vitamin_d3": "25微克（1000IU）", "serving_size": "1顆"}', 27, false, '2026-02-17 15:37:55.858395+00', '2026-02-24 08:37:24.380758+00', 'iHerb 直送。✅ 每日 2 顆（2000IU），無需切割。180 顆可用 3 個月。'),
	('cb1de277-f57f-41fc-9a8e-aa7e8884f834', '銅 Copper Bisglycinate（Solaray 2mg × 100 顆）', '⛔ 已停用 — 15mg 鋅屬安全生理劑量，不會觸發金屬硫蛋白阻斷銅吸收。銅由堅果、可可粉、全穀類天然提供，免除游離銅蓄積導致的神經與肝臟毒性風險', '已停用。不再需要額外補充銅', 'NT$217 / 100 顆', 'https://tw.iherb.com/pr/solaray-copper-2-mg-100-vegcaps/70102', 'iHerb', 'iherb_supplement', 'Solaray', 'https://cloudinary.images-iherb.com/image/upload/f_auto,q_auto:eco/images/sor/sor45931/g/37.jpg', 4.7, 17219, 'SOR-45931', NULL, '{"form": "素食膠囊", "count": "100顆", "chelate_type": "銅氨基酸螯合物"}', '{"copper": "2mg", "serving_size": "1顆"}', 26, false, '2026-02-17 15:37:55.858395+00', '2026-02-17 15:37:55.858395+00', '⛔ 已停用。15mg 鋅不需要搭配銅補劑，銅由天然食物提供。'),
	('430aa42b-a89b-49af-8c9f-e78ff5ca47a7', '全遮光窗簾', '確保臥室全黑環境，維持褪黑激素正常分泌。配合 00:00 入睡方案', '安裝於臥室窗戶', 'NT$1,000~3,000', 'https://www.amazon.com/100-percent-blackout-curtains/s?k=100+percent+blackout+curtains', 'Amazon', 'equipment', NULL, NULL, NULL, NULL, NULL, NULL, '{}', '{}', 39, true, '2026-02-17 15:37:55.858395+00', '2026-02-17 15:37:55.858395+00', '一次性購買。量好窗戶尺寸，選「100% blackout」標示。邊緣可用魔鬼氈輔助密封。'),
	('40df328b-5e1c-49ce-a805-187b653e9ef8', '綠茶（茶葉/茶包）', '低咖啡因白毫銀針或老白毫。EGCG + L-theanine 天然組合促進專注。多酚抗氧化。不含茶多酚氧化產物，溫和不傷腸胃', '每日下午 15:00-15:30 綠茶 2-3 杯（咖啡已移至早晨）', '~NT$200-400', 'https://www.costco.com.tw/Food-Dining/Drinks/Tea/c/90811', 'Costco', 'costco_food', NULL, NULL, NULL, NULL, NULL, NULL, '{}', '{}', 23, true, '2026-02-25 15:46:19.988974+00', '2026-02-25 15:46:19.988974+00', 'Costco 茶飲區或超市購買。散裝綠茶葉 CP 值最高。'),
	('5a3740e2-1d00-4d83-9e6f-18ded29939f2', '特級初榨橄欖油（Kirkland 2L）', '單元不飽和脂肪酸（MUFA）來源，支持脂溶性維他命吸收。抗發炎多酚。產地西班牙', '午餐 1 大匙（14g）+ 晚餐 2 大匙（28g）= 每日共 42g', 'NT$459 / 2L', 'https://www.costco.com.tw/Food-Dining/Groceries/Cooking-Oil-Sauces/c/90903', 'Costco', 'costco_food', 'Kirkland Signature 科克蘭', NULL, NULL, NULL, NULL, '西班牙', '{"volume": "2公升", "storage": "陰涼避光處，開封後 3-6 個月內用完", "ingredients": "100% 特級初榨橄欖油"}', '{"mufa": "約10g", "calories": "約126kcal", "fat_per_15ml": "14g"}', 22, true, '2026-02-25 15:46:19.988974+00', '2026-02-25 15:46:19.988974+00', '線上可訂（常溫配送）。每日 42g，2L（≈1840g）約 1.5 個月用完。⚠️ 建議每 1.5 個月補貨，或趁 Costco 促銷時一次購入 2 瓶（3 個月份）。開封後陰涼避光處保存，3-6 個月內用完。'),
	('d2214a84-4e5f-41da-be09-bd08b9a450d8', '豌豆蛋白 Pea Protein（Tryall 1kg）', '台灣品牌 Tryall，非乳製植物蛋白，中速消化。下午點心時段服用，分散每日蛋白質攝取至 4-5 餐。無大豆、無乳製品、無麩質。與 Tryall 乳清同品牌，品質一致', '下午點心 22g 粉（≈16g 蛋白），約 15:30', '約 NT$800-1,000 / 1kg', 'https://www.tryall.com.tw', 'Costco', 'iherb_supplement', 'TRYALL', NULL, NULL, NULL, NULL, NULL, '{"form": "無調味粉末", "brand": "Tryall", "weight": "1kg", "ingredients": "豌豆蛋白分離物"}', '{"fat": "~2g", "carbs": "~1g", "protein": "~24g", "serving_size": "33g"}', 33, true, '2026-02-25 15:46:19.988974+00', '2026-02-25 15:46:19.988974+00', 'Tryall 官網或 Costco 線上可訂。每日 22g，1kg 可用約 45 天。無調味可搭配少量蜂蜜或可可粉。與 Tryall 乳清同品牌，統一採購更方便'),
	('807cc27b-40a3-4495-a04b-65ecbcd08926', 'Tryall 無調味分離乳清蛋白 2kg', '台灣品牌，無調味無添加。分離乳清蛋白（WPI），約 90% 蛋白質含量，每 30g 粉含 ~27g 蛋白、~120kcal。美國乳源，過濾大部分乳糖與脂肪，乳糖不耐者也適合', '訓練前 1 份（~30g 粉 ≈ 27g 蛋白）。午餐改為正餐蛋白質，不再額外沖乳清', '約 NT$1,899~2,199 / 2kg', 'https://www.costco.com.tw/Health-Beauty/Supplements/Sports-Performance/Tryall-Whey-Protein-Isolate-Unflavored-2-kg/p/155648', 'Costco', 'costco_supplement', 'TRYALL', NULL, NULL, NULL, '155648', '台灣（品牌）/ 美國（乳源）', '{"form": "無調味粉末", "weight": "2kg", "features": "無添加糖、甜味劑、人工色素、香料", "ingredients": "分離乳清蛋白（美國乳源）"}', '{"fat": "~2g", "bcaa": "~5.3g", "carbs": "~3g", "protein": "~27g", "calories": "~120kcal", "protein_pct": "約90%", "serving_size": "30g"}', 21, true, '2026-02-17 15:37:55.858395+00', '2026-02-22 14:32:33.841141+00', 'Costco 線上可訂。每日 ~30g（訓練前 1 份），2kg 約 2 個月。無調味可搭配咖啡、黑芝麻粉等調味。'),
	('2bebaf3b-e310-4225-a08f-1811c637f1e9', '平飼雞蛋（全佑牧場 LL 規格）', '晚餐蛋白質主力（常規日隨晚餐食用，牛肉日 1-2 顆移至午餐、1 顆移至 15:30 下午點心）。富含亮氨酸 Leucine。冷藏平飼蛋，非籠飼。賣場限定商品', '每日嚴格 4 顆（膽鹼 AI 550mg 最低保障）。非牛肉日：1 顆 15:30 + 3 顆晚餐。牛肉日：1-2 顆午餐 + 1 顆 15:30 + 補卵磷脂', '~NT$274 / 30 入', 'https://www.costco.com.tw/Warehouse-Only/Food-Beverages/Chilled/QUAN-YOU-FARM-Cage-Free-Eggs-LL-30-Count/p/128970', 'Costco', 'costco_food', '全佑牧場', NULL, NULL, NULL, NULL, '台灣', '{"count": "30入", "storage": "冷藏 7°C 以下，離開冷藏時間請勿超過30分鐘，開封後請盡速使用", "warehouse_only": true}', '{}', 4, true, '2026-02-17 15:37:55.858395+00', '2026-02-23 09:10:23.687281+00', '賣場限定，無法線上訂。每日 3-4 顆，30 入約 7-10 天。絕對不要把 30 入紙托直接塞冰箱——買一個雙層抽屜式雞蛋盒（寬約 15cm），貼齊冷藏最底層側邊，上方平面還能繼續疊放保鮮盒。'),
	('e2bfe1dc-b783-4d8a-a69d-036a55ab9f61', '雞肝（傳統市場/超市）', '鐵質+預成形維他命A最強食物來源。每 50g 含：血基質鐵 ~5.5mg（吸收率 25-35%）、維他命A ~5,500mcg RAE（視黃醇形式）、B12 ~8.5mcg、葉酸 ~290mcg、銅 ~0.25mg。🔴 嚴格 50g/次、2次/週——100g/次會使週均 preformed retinol 達 3,143mcg/日超 UL 3,000mcg。2×50g = ~1,571mcg/日（安全）。⚠️ BCMO1 基因變異者（45% 人口）β-胡蘿蔔素→視黃醇轉化率極低，雞肝提供直接視黃醇繞過此瓶頸', '每週 2 次午餐入菜（每次嚴格 50g，電子秤量測）。⚠️ 不可超過 50g/次', 'NT$40-60 / 300g', 'https://www.pxmart.com.tw', '傳統市場 / 全聯', 'convenience_daily', NULL, NULL, NULL, NULL, NULL, NULL, '{}', '{"per_50g": "鐵 5.5mg, 維他命A 5500mcg RAE, B12 8.5mcg, 葉酸 290mcg, 銅 0.25mg"}', 58, true, '2026-03-01 10:07:42.112002+00', '2026-03-01 10:07:42.112002+00', '每週買 100g（2 次 × 50g）。新鮮雞肝冷藏 1-2 天，買當天料理最佳。可分 2 份 50g 用保鮮膜包好冷藏。'),
	('634dc374-7f46-4c41-80cb-b585884dfe9f', '椰子水（Vita Coco / Kirkland 330ml）', '天然鉀補充來源，每 330ml 含鉀 ~600mg。系統性彌補每日鉀攝取缺口 250-750mg（食物基線 3,250-3,550mg vs 目標 3,800-4,000mg）。另含鎂 ~60mg、少量鈉。低熱量天然飲品', '每日 1 瓶（330ml），15:30 下午點心時段或訓練後飲用', 'NT$35-55 / 330ml', 'https://www.costco.com.tw/Food-Dining/Drinks/c/90810', 'Costco / 全聯 / 便利超商', 'convenience_daily', NULL, NULL, NULL, NULL, NULL, NULL, '{}', '{"per_330ml": "鉀 ~600mg, 鎂 ~60mg, 熱量 ~50kcal, 糖 ~12g"}', 59, true, '2026-03-01 10:07:42.112002+00', '2026-03-01 10:07:42.112002+00', '每日 1 瓶。Costco 12 瓶裝最划算（~NT$420/12 瓶）。常溫保存。每月約 30 瓶。'),
	('c3a67303-7405-45d0-885f-848d66000bb2', '咖啡豆 / 研磨咖啡', '訓練前飲用，咖啡因 150-200mg + L-Theanine 200mg（A 級 nootropic 組合）。多酚抗氧化、增強專注力。距午餐 2.75hr+，鐵吸收影響極低', '每日 1-2 杯，09:15 訓練前（搭配 L-Theanine 200mg）', '~NT$399 / 1.13kg', 'https://www.costco.com.tw/Coffee-Beans/c/hero_coffeebean', 'Costco', 'costco_food', NULL, NULL, NULL, NULL, NULL, NULL, '{}', '{}', 21, true, '2026-02-17 15:37:55.858395+00', '2026-02-17 15:37:55.858395+00', '賣場咖啡專區。Kirkland 深焙豆 1.13kg 約 $399 最經濟，可用 1-2 個月。開封後密封或冷凍保存。'),
	('cc09ae76-745b-44db-b364-711d48543d0b', '綜合堅果（Kirkland 1.13kg）', '（每日必須）腰果、杏仁、開心果、夏威夷豆、巴西堅果。健康脂肪、鎂、鋅、維他命E、硒來源。🔴 份量：堅果 45g + 南瓜籽 35g + 核桃 15g + 葵花籽 15g = 共 ~110g/日。🟢 鋅補強：南瓜籽 35g 提供 ~2.9mg 鋅，確保非牛肉日鋅攝取 ≥11mg RDA。維他命E 修正：堅果 45g ~5.4mg + 葵花籽 15g ~5.3mg + 核桃 15g ~0.3mg + 橄欖油 42g ~5.9mg + 酪梨 ~0.7mg = ~17.6mg（搭配南瓜籽 35g ~0.7mg = ~18.3mg，達 RDA 15mg）。🔴 Omega-6 改善：葵花籽從 25-30g 減至 15g（減少 ~6.5g omega-6），核桃 15g 提供 ~1.3g ALA omega-3。🔴 鮭魚日嚴格禁止巴西堅果。⚠️ 巴西堅果嚴格 1 顆/日上限', '每日必須（堅果 45g + 南瓜籽 35g + 核桃 15g + 葵花籽 15g = ~110g）', 'NT$599 / 1.13kg', 'https://www.costco.com.tw/Food-Dining/Snacks/Nuts-Jerky/Kirkland-Signature-Mixed-Nuts-113-kg/p/1669722', 'Costco', 'costco_food', 'Kirkland Signature 科克蘭', NULL, NULL, NULL, NULL, '越南', '{"notes": "可能含有堅果碎殼，食用時請小心", "weight": "1.13公斤", "storage": "未開封時請存放於陰涼乾燥處,開封後請冷藏並請儘速食用完畢", "allergens": "本產品含有花生及堅果類製品，食物過敏者請留意", "ingredients": "腰果,杏仁,開心果,夏威夷果仁,巴西堅果,花生油,海鹽"}', '{}', 11, true, '2026-02-17 15:37:55.858395+00', '2026-02-23 09:10:23.687281+00', '每日必須 ~110g。全部集中於 15:30 下午點心食用（避免午晚餐鋅鐵競爭）。線上可訂（常溫配送）。1.13kg 堅果約 3.5 週。另購：南瓜籽 500g + 核桃 500g + 葵花籽 500g（全聯/Costco）。🔴 鮭魚日跳過巴西堅果'),
	('e4dc93db-ee57-4ed9-a8c6-fd004d98a7ab', '防曬乳（Neutrogena/La Roche-Posay SPF 50+）', '廣譜 UVA/UVB 防護，SPF 50+ PA++++。物理+化學防曬，質地清爽不油膩。防曬是#1抗皮膚老化措施', '每日早上外出前，全臉頸部（約1/4茶匙）', 'NT$350-600 / 50-100ml', 'https://www.watsons.com.tw/sunscreen', '屈臣氏/康是美/iHerb', 'personal_care', 'Neutrogena / La Roche-Posay / Biore', NULL, NULL, NULL, NULL, '美國/法國/日本', '{"spf": "SPF 50+ PA++++", "volume": "50-100ml", "features": "廣譜防曬,防水配方"}', '{}', 40, true, '2026-02-26 15:24:39.361326+00', '2026-02-26 15:24:39.361326+00', '屈臣氏/康是美實體購買可試質地。Neutrogena Ultra Sheer約$400/88ml（CP值高），La Roche-Posay Anthelios約$600/50ml（敏感肌），Biore Aqua Rich約$350/50ml（清爽款）。每日使用，50ml約1個月。'),
	('edb1d053-62b3-4d9d-acb5-82f773100a1d', '洗面乳（CeraVe Hydrating Cleanser 236ml）', '胺基酸溫和潔面，含神經醯胺+玻尿酸，不破壞皮膚屏障。pH平衡配方適合每日早晚使用', '早晚各一次，溫水洗臉', 'NT$420 / 236ml', 'https://tw.iherb.com/pr/cerave-hydrating-facial-cleanser-8-fl-oz-236-ml/69325', 'iHerb/屈臣氏/康是美', 'personal_care', 'CeraVe', NULL, NULL, NULL, NULL, '美國', '{"ph": "pH 5.5-6 (接近皮膚自然pH)", "volume": "236ml", "features": "無香料,無皂鹼,低敏配方"}', '{}', 41, true, '2026-02-26 15:24:39.361326+00', '2026-02-26 15:24:39.361326+00', 'iHerb 直送 NT$420/236ml（最划算）。屈臣氏/康是美也有販售但容量較小。每日2次，236ml約3個月。CeraVe 是皮膚科醫師推薦品牌，含神經醯胺修復皮膚屏障。替代品：Cetaphil 溫和潔膚乳（約$400/200ml）。'),
	('ef909965-5f22-4bcd-bf84-3093a8d094f3', '保濕乳液（CeraVe Moisturizing Cream 340g）', '含玻尿酸+神經醯胺+甘油，MVE 緩釋技術24小時保濕。無香料低敏配方，洗臉後立即使用鎖水', '早晚洗臉後立即使用（臉頸部）', 'NT$566 / 340g', 'https://tw.iherb.com/pr/cerave-moisturizing-cream-12-oz-340-g/69326', 'iHerb/屈臣氏/康是美', 'personal_care', 'CeraVe', NULL, NULL, NULL, NULL, '美國', '{"volume": "340g", "features": "MVE緩釋技術,24小時保濕,無香料,無油配方"}', '{}', 42, true, '2026-02-26 15:24:39.361326+00', '2026-02-26 15:24:39.361326+00', 'iHerb 直送 NT$566/340g（大包裝划算）。每日2次，340g約3-4個月。同品牌與洗面乳搭配使用效果佳。替代品：Cetaphil 長效潤膚乳（約$550/350ml）或平價選項如Neutrogena水活保濕凝露（約$300/100g）。'),
	('d558ddd7-18b6-425e-a6e4-727af7af1674', 'A醇精華 0.5% + Vit C 精華（The Ordinary）', 'A醇（晚）：0.5%濃度適合進階使用，促進細胞更新與膠原蛋白生成。Vit C（早）：抗氧化+促進膠原蛋白，防曬前使用增強防護', 'A醇每週2-3次晚上（保濕後），Vit C每日早上（洗臉後）', 'A醇 NT$440/30ml + Vit C NT$550/30ml', 'https://tw.iherb.com/pr/the-ordinary-retinol-0-5-in-squalane-1-fl-oz-30-ml/90058', 'iHerb/屈臣氏', 'personal_care', 'The Ordinary / Timeless', NULL, NULL, NULL, NULL, '加拿大', '{"a醇": "0.5% in Squalane基底,30ml", "vit_c": "20% L-Ascorbic Acid + Vit E + Ferulic Acid,30ml", "storage": "避光陰涼處,Vit C開封後冷藏"}', '{}', 43, true, '2026-02-26 15:24:39.361326+00', '2026-02-26 15:24:39.361326+00', 'iHerb 購買最划算。A醇：從0.2%開始適應→0.5%→1%漸進提升。初期每週1次，無刺激後增至2-3次。若出現脫皮紅癢→暫停數日。Vit C：選L-Ascorbic Acid形式（效果最佳但需冷藏）。開封後3個月內用完避免氧化。兩者不可同時使用（A醇晚，Vit C早）。'),
	('6f9e507d-779f-477a-a8a8-d2c040e8712f', '櫛瓜（美國/加拿大）', '低FODMAP蔬菜，腸胃溫和。富含鉀、維他命C、膳食纖維。替代綠花椰菜避免脹氣', '每日 100-150g 入菜（晚餐優先）', '~NT$100-150 / 300-500g', 'https://www.costco.com.tw/Food-Dining/Frozen-Fresh-Food/Chilled-Fresh-Food/c/90901', 'Costco', 'costco_food', NULL, NULL, NULL, NULL, NULL, '美國/加拿大', '{"portion": "每次 100-150g", "storage": "冷藏 5-7 天，不要水洗後再冷藏", "preparation": "切片或切丁入菜、涼拌皆可"}', '{"per_100g": "17kcal, 蛋白質 1.2g, 碳水 3.1g, 纖維 1.0g, 鉀 261mg"}', 16, true, '2026-02-26 15:24:39.361326+00', '2026-02-26 15:24:39.361326+00', '每週補貨 1-2 次，每次買 500-700g。選外表光滑無軟爛。裝入大保鮮袋平放保鮮抽屜，5-7 天內用完。'),
	('23c2cfb3-58ed-4803-a7de-1ce9d5e8ccff', '電子鍋（多功能）', '⚡ 優先採購（若尚未持有）。煮飯、蒸地瓜/馬鈴薯、燉雞胸肉、煮燕麥粥。一鍋多用是小廚房核心設備。選 3-6 人份（1.0-1.8L 內鍋）適合一人備餐', '每日使用（煮飯、蒸菜、燉肉）', 'NT$1,500-4,000', 'https://www.costco.com.tw/TVs-Electronics/Home-Appliances/Rice-Cookers/c/90118', 'Costco/momo/蝦皮', 'equipment', NULL, NULL, NULL, NULL, NULL, NULL, '{}', '{}', 40, true, '2026-02-26 15:34:21.182411+00', '2026-02-26 15:34:21.182411+00', '⚡ 若尚未持有請優先購入。一次性購買。推薦：象印微電腦電子鍋 3 人份（~$2,500-4,000，煮飯品質佳，有預約定時功能可前晚設定早上煮好）或大同電子鍋 6 人份（~$1,800，經典耐用）。Costco 線上有多款可比較。'),
	('a7c3c409-42a2-4c08-96df-5022f9f0c1bc', '新鮮雞胸肉（冷藏小包）', '超市/全聯冷藏鮮雞胸，300-500g 小包裝。當天購買當天烹調，零冷凍空間佔用', '每週 2-3 次購買，每次 300-500g', 'NT$120-150 / 300g', 'https://www.pxmart.com.tw', '全聯 / 頂好 / 家樂福', 'convenience_daily', NULL, NULL, NULL, NULL, NULL, '台灣', '{"cooking": "當天購買建議當天烹調", "packaging": "冷藏真空包", "shelf_life": "冷藏3-5天"}', '{"fat": "約3g/100g", "protein": "約31g/100g", "calories": "約165kcal/100g"}', 52, true, '2026-02-26 16:40:52.050237+00', '2026-02-26 16:40:52.050237+00', '✅ 唯一雞胸方案（方案 B）：每週 2-3 次購買 300-500g（每次約 NT$120-150）。優點：釋放 Costco 5kg 冷凍佔用的 2-3L 冷凍空間、保證新鮮度、不需「當天全煮 5kg→分裝」流程。每月成本約 NT$1,200-1,500。冷凍庫空間留給鮭魚與其他高價值食材。'),
	('3a8a0f42-dc4e-4aba-b5e2-2865dee1acc3', '鈣片備用（Nature Made Ca+D3+K2 250 錠）', '碳酸鈣 + 檸檬酸鈣雙鈣源。每日 17:00 服用（距 15:30 堅果鋅 1.5hr，距 19:00 晚餐鐵 2hr）。注意：本品含 D3 150IU/錠，與獨立 D3 2000IU 疊加後總計 2150IU 仍在安全範圍。K2 僅 10mcg/錠（不足日需量，已改用獨立 K2 MK-7 100mcg）', '每日 17:00 服用 1 錠（+500mg 鈣）。距 15:30 堅果鋅 1.5hr（鋅腸道吸收完畢），距 19:00 晚餐鐵 2hr（鈣片已離開腸道），距睡前鎂 5.5hr（無競爭）', 'NT$759 / 250 錠', 'https://www.costco.com.tw/Health-Beauty/Supplements/Supplements-Digestive-Support/Nature-Made-Calcium-500-mg-with-D3-K2-250-Tablets/p/228453', 'Costco', 'costco_supplement', 'NATURE MADE 萊萃美', NULL, NULL, NULL, NULL, '美國', '{"form": "錠劑", "count": "250錠", "storage": "請置於陰涼乾燥處，開封後請置於冰箱儲存。", "allergens": "不添加麩質、防腐劑、化學色素及人工香料。", "ingredients": "碳酸鈣(碳酸鈣、麥芽糊精(玉米)、阿拉伯膠)、檸檬酸鈣、微結晶纖維素、維生素K2(麥芽糊精(玉米)、納豆脂質、維生素K2(Menaquinone-7))、羥丙基甲基纖維素、二氧化鈦(著色劑)、聚糊精、硬脂酸鎂、二氧化矽、交聯羧甲基纖維素鈉、滑石粉、麥芽糊精、維生素D3(辛烯基丁二酸鈉澱粉、糖、L-抗壞血酸鈉(抗氧化劑)、二氧化矽、中鏈三酸甘油酯、生育醇(抗氧化劑)、膽鈣化醇)、脂肪酸甘油酯(乳化劑)"}', '{"calcium": "500mg/錠", "vitamin_d3": "3.75mcg (150IU)/錠", "vitamin_k2": "10mcg (MK-7型)/錠"}', 2, true, '2026-02-17 15:37:55.858395+00', '2026-02-24 08:37:24.380758+00', '線上可訂（常溫配送）。250 錠用法：每週 2-3 次隨午餐服用（週二、週四、週六），每次 1 錠。250 錠可用 1-2 年。碳酸鈣+檸檬酸鈣錠劑常溫陰涼處穩定保存。⚠️ 補錠日注意 D3 疊加：備錠含 150IU D3，3×/週 = 450IU 額外，加上獨立 2000IU 補充 = 總 2450IU（仍在 4000IU UL 內，安全）。'),
	('d9750906-a49b-47bc-bd88-8d9e92f994ac', '香蕉（單顆，已熟）', '便利超商每日新鮮香蕉，已達最佳熟度。訓練前快速碳水，富含鉀（每根 ~400mg）', '訓練前 1-2 根，或每日點心', 'NT$10-12 / 根', 'https://www.7-11.com.tw', '7-Eleven / 全家便利店', 'convenience_daily', NULL, NULL, NULL, NULL, NULL, '台灣 / 菲律賓', '{"storage": "常溫1-2天或冷藏3-4天", "ripeness": "已熟即食"}', '{"carbs": "約27g/根", "calories": "約105kcal/根", "potassium": "約400mg/根"}', 50, true, '2026-02-26 16:40:52.050237+00', '2026-02-26 16:40:52.050237+00', '每 2-3 天買 1-2 根。優點：零熟度追蹤、即買即食。比 Costco 散裝 1.4kg 每根貴 NT$2-4，但省冰箱空間 + 保證熟度。訓練日建議每日採購。'),
	('126fe643-ba6a-418c-a111-9e51fba73454', '茶葉蛋', '便利超商現煮茶葉蛋，架穩定蛋白質來源。每顆 ~6.3g 蛋白，適合緊急補充或午餐搭配', '每日 1-2 顆作為蛋白質補充', 'NT$8-12 / 顆', 'https://www.7-11.com.tw', '7-Eleven / 全家便利店 / OK便利店', 'convenience_daily', NULL, NULL, NULL, NULL, NULL, '台灣', '{"protein": "約6.3g/顆", "shelf_life": "冷藏櫃24-48小時"}', '{"fat": "5g/顆", "sodium": "約200-300mg（鹹味）", "protein": "6.3g/顆"}', 51, true, '2026-02-26 16:40:52.050237+00', '2026-02-26 16:40:52.050237+00', '每 2-3 天買 1-2 顆。優點：熟食即食、不佔冷藏（架穩定）、補充 Costco 生蛋不足。注意鹽分較高，每日 1-2 顆為限。每月約 20 顆（NT$160-240）+ Costco 生蛋 20 顆/月，總成本約 Costco 30 顆價格，但省蛋盒空間。'),
	('bd9f455d-733a-40ce-be55-139ef86f1311', '藍莓 / 冷凍莓果', '抗氧化花青素含量最高的水果之一。搭配燕麥碗、希臘優格食用。改善認知功能與心血管健康', '每日 50-100g（燕麥碗或優格搭配）', '新鮮 ~NT$399/510g 或 冷凍 ~NT$329/600g', 'https://www.costco.com.tw/Food-Dining/Frozen-Fresh-Food/Chilled-Fresh-Food/c/90901', 'Costco', 'costco_food', NULL, NULL, NULL, NULL, NULL, '美國/加拿大/智利', '{"storage": "新鮮冷藏3-5天，冷凍版-18°C長期保存"}', '{"fiber": "約2.4g/100g", "vitamin_c": "約10mg/100g", "anthocyanins": "花青素豐富"}', 24, true, '2026-02-26 15:34:21.182411+00', '2026-02-26 15:34:21.182411+00', '新鮮藍莓在 Costco 蔬果區（季節性）。小冰箱建議買新鮮版每週 1 盒（510g），放保鮮抽屜 3-5 天用完。若買冷凍版（Nature''s Touch 600g），僅佔冷凍約 0.5L 可接受。'),
	('289bc3bd-efda-4aaf-a3d2-54141bfd0d3a', '1/4 茶匙不鏽鋼量勺', '（非必要品）其他調味料粗略量測用途。⚠️ 不適合碘鹽精確測量：1/4 茶匙實測約 1.4g（非 1g），誤差 40%。碘鹽精確測量請使用食品電子秤（0.1g 精度）', '（備用）其他調味料或烘焙粗略量測，非碘鹽使用', 'NT$50-150', 'https://www.amazon.com/measuring-spoons-stainless-steel/s?k=measuring+spoons+stainless+steel', 'Amazon', 'equipment', NULL, NULL, NULL, NULL, NULL, NULL, '{}', '{}', 41, true, '2026-02-27 17:09:49.408446+00', '2026-02-27 17:09:49.408446+00', '（可選）若已有食品電子秤則無需購買。⚠️ 碘鹽（每日 1g）必須使用食品電子秤測量（精度 0.1g），量勺誤差過大不可用於碘鹽。量勺僅適合調味料/烘焙等不需精確的場合。'),
	('ea4deec7-6603-4c54-b6eb-1190f4ae5758', '酪梨（單顆，已熟）', '便利超商/全聯單顆酪梨，已達最佳熟度（輕捏微軟）。健康脂肪 + 鉀（~700mg/顆）', '每 2-3 天 1 顆，午餐或晚餐', 'NT$25-30 / 顆', 'https://www.7-11.com.tw', '7-Eleven / 全聯', 'convenience_daily', NULL, NULL, NULL, NULL, NULL, '台灣 / 紐西蘭', '{"storage": "冷藏1-2天", "ripeness": "已熟即食"}', '{"fat": "約15g/半顆", "fiber": "約7g/顆", "potassium": "約700mg/顆"}', 53, true, '2026-02-26 16:40:52.050237+00', '2026-02-26 16:40:52.050237+00', '每 2-3 天買 1 顆（每週 3-4 顆）。優點：零氧化浪費（不需矽膠套保鮮）、熟度保證。比 Costco 1.3kg（4-5 顆）週購貴約 NT$20-40/顆，但省冷藏空間 + 切半保鮮負擔。每月約 12-16 顆（NT$300-480）。'),
	('2bdfc39d-82ee-4b9d-9fba-7cdfe5333154', '新鮮藍莓（小盒）', '便利超商小盒藍莓 150-200g，花青素豐富。搭配燕麥碗、希臘優格', '每週 2-3 次，每次 50-100g', 'NT$99-129 / 150-200g', 'https://www.7-11.com.tw', '7-Eleven / 全家便利店', 'convenience_daily', NULL, NULL, NULL, NULL, NULL, '美國 / 智利', '{"packaging": "透明盒裝", "shelf_life": "冷藏3-5天"}', '{"fiber": "約2.4g/100g", "vitamin_c": "約10mg/100g", "anthocyanins": "花青素豐富"}', 54, true, '2026-02-26 16:40:52.050237+00', '2026-02-26 16:40:52.050237+00', '每週 2-3 次買 1 小盒（每週 300-450g）。優點：不需週購 Costco 510g 大盒（3-5 天吃完壓力）、小量新鮮。成本約 Costco ±0，但省冷藏抽屜空間。'),
	('2f9fb209-5317-4759-9e9e-88fe77c64e1c', '鮪魚罐頭（水煮）', '架穩定蛋白質備用來源。每罐 ~25g 蛋白，適合緊急午餐或晚餐補充', '備用（每月 2-4 罐）', 'NT$50-80 / 罐（約 180g）', 'https://www.7-11.com.tw', '7-Eleven / 全家便利店 / 全聯', 'convenience_daily', NULL, NULL, NULL, NULL, NULL, '泰國 / 台灣', '{"type": "水煮鮪魚（低鈉）", "storage": "常溫", "shelf_life": "未開封2-3年"}', '{"fat": "約1g/罐", "sodium": "約200-400mg（視品牌）", "protein": "約25g/罐"}', 56, true, '2026-02-26 16:40:52.050237+00', '2026-02-26 16:40:52.050237+00', '備用品。當無法採購新鮮蛋白質時（雞胸、鮭魚、蛋缺貨），2 罐鮪魚 = 50g 蛋白可替代一餐。建議常備 2-4 罐（常溫不佔冰箱）。'),
	('9f6c0770-c81c-4e43-b531-99eac03c3d03', '肌酸 Creatine Monohydrate（CGN 454g）', '養肌肉 + 養腦，改善認知與工作記憶', '每日 5g 溶於午餐湯/飲品（12:00 隨餐），碳水+胰島素促進肌酸攝取。已從 09:15 訓練前移出（避免與咖啡因同服）。454g ÷ 5g = 90 天', 'NT$420 / 454g', 'https://tw.iherb.com/pr/california-gold-nutrition-sport-creatine-monohydrate-unflavored-1-lb-454-g/71026', 'iHerb', 'iherb_supplement', 'California Gold Nutrition', 'https://cloudinary.images-iherb.com/image/upload/f_auto,q_auto:eco/images/cgn/cgn01059/g/144.jpg', 4.8, 29306, 'CGN-01059', NULL, '{"form": "無調味粉末", "weight": "454g", "ingredients": "一水肌酸"}', '{"serving_size": "5g", "creatine_monohydrate": "5g"}', 22, true, '2026-02-17 15:37:55.858395+00', '2026-02-17 15:37:55.858395+00', 'iHerb 直送。每日 5g，454g 可用 90 天（3 個月）。⚠️ 建議設定每 3 個月定期補貨提醒。CGN 自有品牌常有額外折扣。搭配其他 iHerb 品項湊免運。'),
	('7009d62e-5971-4b96-9a11-a74abe606248', '乾海帶（昆布）/ 紫菜', '❌ 已停用。昆布碘含量極高且波動極端，不宜作為日常碘來源。與 Ashwagandha 併用甲狀腺風暴風險', '偶爾配菜（每週 0-1 次）：海帶味噌湯（1-2g 乾昆布）或涼拌紫菜（1 片）', 'NT$50-150 / 包', 'https://www.costco.com.tw/Food-Dining/Frozen-Fresh-Food/c/90901', '全聯 / 傳統市場 / Costco', 'convenience_daily', NULL, NULL, NULL, NULL, NULL, '日本/韓國/台灣', '{"portion": "每次 1-2g 乾重（控制碘攝取）", "storage": "常溫密封保存 6-12 個月", "varieties": "昆布（煮湯用）、海帶芽（涼拌用）、紫菜/海苔（直接食用或入湯）"}', '{"per_5g_dry": "碘 1500-15000mcg, 鈣 ~35mg, 鐵 ~0.5mg, 膳食纖維 ~1.5g"}', 17, false, '2026-02-27 19:43:28.137356+00', '2026-02-27 19:43:28.137356+00', '❌ 已停用購買。不購買昆布：碘含量極高且波動極端（1-2g 乾重 = 300-6000mcg，遠超 UL 1100mcg/日），日常已用碘鹽達 RDA。⚠️ 與 Ashwagandha（KSM-66）併用時風險更高：Ashwagandha 可能上調甲狀腺激素（T4），不穩定且巨量的昆布碘劑量 → 甲狀腺機能亢進甚至甲狀腺風暴。碘攝取策略改為：(1) 精確量化 09:05 碘鹽 1g（電子秤測量）(2) 補足每週 2-3 次紫菜/海苔 1-2 片（每片 12-43mcg，安全可控）。碘來源必須穩定與可預測。常溫存放，開封後放密封袋/罐。'),
	('23298442-01fa-4934-8499-2d211c3ca3ed', '新鮮菠菜（沙拉包）', '便利超商預洗菠菜沙拉包 100-150g。低 FODMAP 蔬菜，鉀、鎂、鐵來源', '每週 2-3 次，每次 100-150g', 'NT$30-50 / 100-150g', 'https://www.7-11.com.tw', '7-Eleven / 全家便利店', 'convenience_daily', NULL, NULL, NULL, NULL, NULL, '台灣', '{"packaging": "預洗沙拉包", "shelf_life": "冷藏2-3天"}', '{"iron": "約2.7mg/100g", "magnesium": "約79mg/100g", "potassium": "約558mg/100g"}', 55, true, '2026-02-26 16:40:52.050237+00', '2026-02-26 16:40:52.050237+00', '每週補貨 2 次，每次買 400-500g（支撐每日 100-150g 入菜量，每週需 700-1050g）。放入大保鮮袋、裡面墊一張廚房紙巾吸濕，平放於保鮮抽屜底部，3-5 天內用完。小冰箱用戶不建議買 Costco 冷凍版（500g×6 佔冷凍室 70%）'),
	('020a5e1b-9213-4645-b531-2bb0928c556f', '有機白米（銀川一等白米 3kg）', '花蓮產有機白米。低纖維碳水，訓練日30-40%替代糙米以減輕腸胃負擔。易消化，GI較高適合訓練後補充', '訓練日適量（目標總碳水30-40%來自低纖維）', 'NT$320-380 / 3kg', 'https://www.costco.com.tw/Food-Dining/Groceries/Rice-Noodles/c/hero_rice', 'Costco', 'costco_food', '銀川', NULL, NULL, NULL, NULL, '台灣（花蓮）', '{"weight": "3公斤", "ingredients": "有機白米"}', '{"gi": "中高GI（約73）", "fiber": "低纖維（<1g/100g）"}', 25, true, '2026-02-26 15:24:39.361326+00', '2026-02-26 15:24:39.361326+00', '線上可訂（常溫配送）。3kg約3-6週。開封後密封避免蟲害，夏天建議冷藏。'),
	('41749c2f-c824-4cea-a5cd-fe8277a5afe4', '義大利麵（Garofalo 500g×6）', '義大利進口杜蘭小麥義大利麵。低纖維碳水，訓練日30-40%替代全麥麵食。煮熟後冷卻可產生抗性澱粉', '訓練日適量（作為低纖維碳水選項）', 'NT$459 / 500g×6', 'https://www.costco.com.tw/Food-Dining/Groceries/Rice-Noodles/Garofalo-Penne-Rigate-Pasta-500-g-X-6-Pack/p/117346', 'Costco', 'costco_food', 'Garofalo', NULL, NULL, NULL, NULL, '義大利', '{"count": "500g × 6包", "weight": "3公斤", "storage": "常溫陰涼乾燥處", "ingredients": "杜蘭小麥粉"}', '{"gi": "中GI（約55-65，視煮熟度）", "fiber": "低纖維（約2-3g/100g乾麵）", "protein": "約12g/100g"}', 26, true, '2026-02-26 15:24:39.361326+00', '2026-02-26 15:24:39.361326+00', '線上可訂（常溫配送）。500g×6共3kg，可用1-2個月。開封後每包密封防潮。常溫存放不佔冰箱空間。Costco另有其他品牌（Barilla, De Cecco）可替換。'),
	('2b5f7249-f349-43c2-89db-ef9aa465b15e', '馬鈴薯（美國/加拿大）', '去皮後低纖維碳水 + 鉀質主力（每顆 ~800mg 鉀）。與酪梨共同修復鉀缺口。訓練日 30-40% 替代地瓜。冷卻後產生抗性澱粉。選擇黃皮或紅皮較甜', '每日 1 顆（去皮烹調），訓練日作為低纖維碳水選項', '~NT$199 / 3kg', 'https://www.costco.com.tw/Food-Dining/Frozen-Fresh-Food/Chilled-Fresh-Food/c/90901', 'Costco', 'costco_food', NULL, NULL, NULL, NULL, NULL, '美國/加拿大', '{"notes": "發芽或變綠的馬鈴薯含有毒素（龍葵鹼），務必丟棄", "storage": "陰涼通風處，勿冷藏（會轉甜並影響質地）"}', '{"gi": "中高GI（約85-90，視烹調法）", "fiber": "去皮後低纖維（約1g/100g）", "potassium": "約800mg/顆"}', 27, true, '2026-02-26 15:24:39.361326+00', '2026-02-26 15:24:39.361326+00', '賣場蔬果區散裝，約NT$199/3kg（6-8顆）。選外皮光滑無發芽。常溫通風處可放2-3週，勿冷藏。每週補1次約可用7-10天。'),
	('283e520a-96e0-42da-9832-a55e8f3f3986', '碘鹽（統一生機 日曬海鹽加碘）', '西班牙日曬海鹽 + 碘化鉀。海鹽/玫瑰鹽碘含量極低，十字花科蔬菜攝取量高時需確保碘攝取', '日常用鹽，每日少許', 'NT$179 / 2kg', 'https://www.costco.com.tw/Food-Dining/Groceries/Cooking-Oil-Sauces/Uni-President-Iodized-Solar-Sea-Salt-2-kg/p/283283', 'Costco', 'costco_food', '統一生機', NULL, NULL, NULL, NULL, '西班牙', '{"notes": "不添加抗結塊劑，若有輕微結塊，品質無虞請安心食用。", "weight": "2公斤", "storage": "常溫", "allergens": "本產品與其它含有芒果、大豆、奶類、含麩質之穀物、魚、堅果、芝麻、蕎麥及甲殼類的產品於同一工廠生產，食物過敏者請留意。", "ingredients": "日曬海鹽、碘化鉀"}', '{}', 9, true, '2026-02-17 15:37:55.858395+00', '2026-02-17 15:37:55.858395+00', '線上可訂（常溫配送）。2kg 約可用 6 個月以上。⚠️ 務必確認為「加碘」版本（包裝標示「碘化鉀」成分）。海鹽/玫瑰鹽碘含量極低。'),
	('1556d6df-a1c3-4c3c-bc62-7a4f884c604f', 'B群 活化型態（NOW Foods B-50 Coenzyme 60 顆）', '活化型態 B 群：甲基鈷胺素（B12）、5-MTHF（葉酸）、P5P（B6 50mg）。⚠️ P5P 50mg/日長期有周邊神經病變風險（>25mg/日文獻個案）。🔴 建議方案：(A) 換用 ≤25mg B6 的 B-complex（如 Thorne Basic B Complex），每日服用（均 25mg/日，安全）。(B) 若繼續使用本品，改為每 3 天 1 顆（均 ~17mg/日）。每月自檢手腳麻木/刺痛。每半年健檢包含 B6 水平', '每 3 天 1 顆隨午餐服用（P5P 50mg，均 ~17mg/日——低於神經病變風險閾值 25mg）。或換用 ≤25mg B6 產品後恢復每日服用', 'NT$450-550 / 60 顆', 'https://tw.iherb.com/pr/now-foods-coenzyme-b-complex-60-veg-capsules/14804', 'iHerb', 'iherb_supplement', 'NOW Foods', 'https://cloudinary.images-iherb.com/image/upload/f_auto,q_auto:eco/images/now/now00420/g/74.jpg', 4.7, NULL, 'NOW-00427', NULL, '{"form": "素食膠囊", "type": "Coenzyme（活化型態）", "count": "60顆"}', '{"b6": "P5P（活化型態）", "b12": "甲鈷胺 Methylcobalamin", "folate": "5-MTHF（非 Folic Acid）", "serving_size": "1顆"}', 32, true, '2026-02-25 12:20:10.271551+00', '2026-02-25 12:20:10.271551+00', 'iHerb 必買品項。✅ 活化型態（Coenzyme）優於普通合成 B-50：甲鈷胺 B12（非氰鈷胺）、5-MTHF 葉酸（非 Folic Acid，應對 MTHFR 基因變異）、P5P B6。60 顆可用 2 個月。⚠️ 已改為 12:00 午餐隨餐服用（非訓練前）'),
	('3c6ab45a-df52-48f2-8222-d7f0c8636793', 'Ashwagandha KSM-66（NOW Foods 90 顆）', 'KSM-66 全譜根部萃取，降低皮質醇、改善壓力與睡眠品質。RCT 支持的適應原草藥', '睡前 1 顆（450mg）。8 週用 / 4 週停', 'NT$288 / 90 顆', 'https://tw.iherb.com/pr/now-foods-ashwagandha-standardized-extract-450-mg-90-veg-capsules/310', 'iHerb', 'iherb_supplement', 'NOW Foods', 'https://cloudinary.images-iherb.com/image/upload/f_auto,q_auto:eco/images/now/now04603/g/83.jpg', 4.7, NULL, 'NOW-04603', NULL, '{"form": "素食膠囊", "count": "90顆", "extract": "KSM-66 全譜根部萃取"}', '{"serving_size": "1顆", "ashwagandha_extract": "450mg"}', 36, true, '2026-02-25 15:46:19.988974+00', '2026-02-25 15:46:19.988974+00', 'iHerb 直送。每瓶 90 顆可完成 1 個完整週期（56 顆用 + 剩 34 顆留下一輪）。建議在瓶身標記「開始日」與「第 56 天停用日」。'),
	('5144f72b-4575-4339-afda-c615ca64e309', '有機燕麥（桂格有機大燕麥片 935g×2）', '澳洲有機燕麥，已完全煮熟。β-葡聚醣降膽固醇，優質碳水 + 膳食纖維 8g/份（GI~55，中升糖）。⚠️ 含植酸（Phytic Acid），會螯合鋅、鐵、鈣等二價礦物質。若餐後立即食用燕麥（與鋅同時進行），植酸在胃腸中直接與鋅離子結合，導致晚餐鋅 15mg 吸收率 0%。因此燕麥必須分散至早晨/午餐食用，與晚間 19:00 鋅補劑至少間隔 3-4 小時', '休息日早/午餐每日 1 份（80g）；訓練日改置於 15:30 下午點心搭配豌豆蛋白 + 藍莓', 'NT$439 / 935g×2', 'https://www.costco.com.tw/Food-Dining/Drinks/Powdered-Drink-Mix-Cereal-Oats/Quaker-Organic-Whole-Oats-935-g-X-2-Count/p/116958', 'Costco', 'costco_food', 'QUAKER 桂格', NULL, NULL, NULL, NULL, '澳洲（原料）/ 台灣（製造）', '{"weight": "935公克 X 2入", "cooking": "直接將本產品置於250c.c.熱開水中三分鐘，均勻攪拌即可。", "storage": "開封前請置於乾燥陰涼處，開封後請盡速食用完畢。", "allergens": "本產品含有含穀蛋白之穀物(燕麥)。", "ingredients": "有機燕麥(澳洲)。"}', '{"gi": "約55（中升糖）", "fiber": "8g/份"}', 17, true, '2026-02-17 15:37:55.858395+00', '2026-02-17 15:37:55.858395+00', '線上可訂（常溫配送）。每日 80g，935g×2 約 23 天，每月補一次。⚠️ 關鍵：燕麥含植酸，晚餐避開（晚餐補鋅 19:00）。改為早晨（09:15 訓練前點心、或搭配 08:00 新鮮地瓜）、或午餐食用。與晚餐鋅至少間隔 3-4 小時。開封後密封避免受潮。'),
	('b0b8c5aa-cee5-4d58-9127-de6c9a8c42be', '電解質粉 Sport Hydration（CGN 20 包）', '鈉、鉀、鎂、鈣電解質補充。有氧訓練日維持水合與電解質平衡', '有氧日訓練中 2 包分次沖泡（09:05 預沖 1 包 500ml + 訓練中途 1 包 500ml）。⚠️ 從 1 包升級為 2 包——單包僅補回 25% 汗液鈉損失', 'NT$600 / 20 包', 'https://tw.iherb.com/pr/california-gold-nutrition-hydrationup-electrolyte-drink-mix-variety-pack-20-packets-0-14-oz-0-17-oz-4-g-4-8-g-each/94823', 'iHerb', 'iherb_supplement', 'California Gold Nutrition', 'https://cloudinary.images-iherb.com/image/upload/f_auto,q_auto:eco/images/cgn/cgn01402/g/75.jpg', 4.5, NULL, 'CGN-01402', NULL, '{"form": "沖泡粉末", "count": "20包"}', '{"sodium": "250mg", "potassium": "150mg", "serving_size": "1包"}', 37, true, '2026-02-25 15:46:19.988974+00', '2026-02-25 15:46:19.988974+00', 'iHerb 直送。20 包約 5 週（每週 2 天 × 2 包 = 4 包/週）。💡 建議一次購入 4 盒（5 個月份）。CGN 自有品牌有折扣。'),
	('5bd46d7c-3402-44b7-b512-a6dbe46f1f08', '維他命 K2 MK-7（NOW Foods 100mcg × 120 顆）', '獨立 K2 MK-7（納豆來源），引導鈣質沉積至骨骼而非血管壁。與 D3 協同作用，防止動脈鈣化。🔴 已移至晚餐（19:00，搭配 28g 橄欖油）——午餐僅 14g 橄欖油，晚餐 28g 提供更充足脂質微膠粒，脂溶性維生素吸收提升 30-50%', '每日 1 顆隨晚餐（19:00）服用——從午餐移至晚餐，28g 橄欖油提供更充足脂質載體提升脂溶性 K2 吸收。MK-7 半衰期 ~72hr，每日 1 次即可', 'NT$887 / 120 顆', 'https://tw.iherb.com/pr/now-foods-mk-7-vitamin-k-2-100-mcg-120-veg-capsules/78992', 'iHerb', 'iherb_supplement', 'NOW Foods', 'https://cloudinary.images-iherb.com/image/upload/f_auto,q_auto:eco/images/now/now00993/g/86.jpg', 4.8, NULL, 'NOW-00993', NULL, '{"form": "素食膠囊", "count": "120顆", "source": "MK-7（納豆來源）"}', '{"vitamin_k2": "100mcg（MK-7型）", "serving_size": "1顆"}', 28, true, '2026-02-26 15:34:21.182411+00', '2026-02-26 15:34:21.182411+00', 'iHerb 直送。每日 1 顆，120 顆可用 4 個月。'),
	('92d9f58c-cffc-485e-b1e2-51f04a00c52d', 'CoQ10 Ubiquinol 200mg（NOW Foods 60 顆）', '還原型輔酶 Q10（Ubiquinol），生物利用率高於 Ubiquinone。支持細胞能量產生與心血管健康。脂溶性，與魚油同服提升吸收。📋 已移至晚餐服用（28g 橄欖油提供更充足脂質）。⚠️ 每季評估必要性：23 歲健康男性 CoQ10 缺乏風險極低（主要適用於 40 歲以上或服用 Statin 類藥物者）。若血檢正常且無疲勞感，可考慮停用以減少補充品總量（目前 18-20 種/日，建議降至 10-12 種）', '每日 1 顆隨 19:00 晚餐（搭配 28g 橄欖油增強脂溶性吸收）', 'NT$1,109 / 60 顆', 'https://tw.iherb.com/pr/now-foods-ubiquinol-200-mg-60-softgels/23657', 'iHerb', 'iherb_supplement', 'NOW Foods', 'https://cloudinary.images-iherb.com/image/upload/f_auto,q_auto:eco/images/now/now03144/g/38.jpg', 4.8, NULL, 'NOW-03144', NULL, '{"form": "軟膠囊", "count": "60顆"}', '{"ubiquinol": "200mg", "serving_size": "1顆"}', 31, true, '2026-02-25 12:20:10.271551+00', '2026-02-25 12:20:10.271551+00', 'iHerb 直送。每日 1 顆，60 顆可用 2 個月。'),
	('a70388aa-d731-40b0-bbfe-b84acbc0cde1', '維他命 D3 1000IU（NOW Foods 180 顆）', '每日服用 2 顆（2000 IU）。Endocrine Society 建議 1500-2000 IU/日，目標血清 25(OH)D 40-60 ng/mL。血檢達標+每日晨光曝曬→可進一步減量。✅ 1000IU 軟凝膠，每日 2 顆', '每日 2 顆（2000 IU）隨訓練後餐（需搭配油脂吸收）', 'NT$300-400 / 180 顆', 'https://tw.iherb.com/pr/now-foods-vitamin-d3-1000-iu-180-softgels/3882', 'iHerb', 'iherb_supplement', 'NOW Foods', NULL, NULL, NULL, NULL, NULL, '{"form": "軟膠囊", "vitamin_d3": "1000 IU (25mcg) / 顆"}', '{"vitamin_d3": "1000 IU / 顆"}', 9, false, '2026-03-01 00:52:08.841207+00', '2026-03-01 00:52:08.841207+00', 'iHerb 直送。✅ 每日 2 顆（2000IU），無需切割。180 顆可用 3 個月。'),
	('e6cd256e-0fb4-40a7-bfe5-4e9f4f09b41f', '碘補充劑 75mcg（NOW Foods 120 錠）', '❌ 關鍵缺失補充。當前策略（碘鹽 1g + 海苔 1-2 片）僅提供 32-76mcg，遠低於 RDA 150mcg。本補充劑解決長期碘缺乏風險（導致甲狀腺功能減退、認知下降）', '每日 1 錠隨早餐或午餐', 'NT$250-350 / 120 錠', 'https://tw.iherb.com/pr/now-foods-iodine-150-mcg-120-tablets/3945', 'iHerb', 'iherb_supplement', 'NOW Foods', NULL, NULL, NULL, NULL, NULL, '{"UL": "1100mcg/day", "count": "120 tablets", "iodine": "75mcg per tablet (Kelp source)"}', '{"iodine": "75mcg / 錠"}', 8, true, '2026-03-01 00:52:08.841207+00', '2026-03-01 00:52:08.841207+00', '❗ 立即購入。碘鹽 1g 提供 20-33mcg + 海苔 1-2 片提供 12-43mcg = 32-76mcg（缺陷 67-118mcg vs RDA 150mcg）。添加 75mcg 補充 → 總量 107-151mcg（達 RDA）。選擇昆布來源（Kelp）而非合成 KI 以確保天然形式。每 120 錠可用 4 個月。安全性：75mcg 遠低於 UL 1100mcg。'),
	('eba8f020-49d3-4b0c-a286-fcfd74ebfc7c', '維他命 D3 2000IU（NOW Foods 180 顆）', '由羊毛脂提取，膽鈣化醇形式（最活躍的 D3 形式）。每顆 2000 IU。絕對符合 Endocrine Society 2022 指引下限（針對亞熱帶強力運動員）。', '每日 1 顆隨午餐（與魚油、K2、葉黃素、CoQ10 同服，脂溶性需油脂載體）', 'NT$400-500 / 180 顆', 'https://tw.iherb.com/pr/now-foods-vitamin-d-3-2000-iu-180-softgels/3755', 'iHerb', 'iherb_supplement', 'NOW Foods', NULL, NULL, NULL, NULL, 'USA', '{"form": "軟膠囊", "count": "180粒", "storage": "請存放於乾燥陰涼處，開封後請旋緊瓶蓋。", "ingredients": "膽鈣化醇(維生素D3)"}', '{"vitamin_d3": "2000IU/膠囊"}', 40, true, '2026-03-01 02:53:29.154533+00', '2026-03-01 02:53:29.154533+00', 'iHerb 直送。✅ 每日 1 顆（2000 IU），免切免推藥器。180 顆可用 6 個月。開瓶後標記日期，12 個月內用完。⚠️ 與現有 1000 IU 版本區別：新規格為 2000 IU 單顆。'),
	('1bcba357-73e9-47dd-9f68-a48b87366688', '希臘優格（Kirkland 零脂 907g×2）', '5 種活菌（保加利亞乳桿菌、嗜熱鏈球菌、嗜酸乳桿菌、雙歧桿菌、乾酪乳桿菌）。零脂，每 100g 含 9.4g 蛋白質。賣場限定商品', '每日 300g（必須）', 'NT$479 / 907g×2', 'https://www.costco.com.tw/Warehouse-Only/Food-Beverages/Chilled/Kirkland-Signature-Chilled-Nonfat-Greek-Yogurt-907-g-X-2-Count/p/599369', 'Costco', 'costco_food', 'Kirkland Signature 科克蘭', NULL, NULL, NULL, NULL, '美國', '{"notes": "無防腐劑、無色素、無麩質、無人工香料、無添加糖", "weight": "907公克 X 2入", "storage": "冷藏 4°C 以下，開封後請盡速食用完畢", "allergens": "本產品含牛奶，食物過敏者請留意", "ingredients": "巴氏殺菌發酵脫脂牛奶(巴氏殺菌脫脂牛奶,乳酸菌), 乳酸菌(Lactobacillus bulgaricus, Streptococcus thermophilus, Lactobacillus acidophilus, Bifidobacterium lactis, Lactobacillus casei)", "warehouse_only": true}', '{"protein_per_100g": "9.4g"}', 12, true, '2026-02-17 15:37:55.858395+00', '2026-02-23 09:10:23.687281+00', '賣場限定，無法線上訂。每日 300g（必須），907g×2 約 6 天，每週補貨。兩罐圓筒無法改形狀，緊靠冷藏室最上層深處放置（最低溫區），前方空間留給泡菜疊放。');
